var _otChapterHeadingsHeb = {
  "Genesis 1": "אלוהים בורא את הארץ הזאת ואת השמים שלה ואת כל צורות החיים בשישה ימים - מעשי היצירה של כל יום מתוארים - אלוהים בורא את האדם, זכר ונקבה כאחד, בצלמו שלו - האדם מקבל שליטה על כל הדברים והוא מצווה להתרבות ולמלא את הארץ.",
  "Genesis 2": "הבריאה הושלמה - אלוהים נח ביום השביעי - בריאת הרוח הקודמת מוסברת - אדם וחוה ממוקמים בגן העדן - אסור להם לאכול מעץ הדעת טוב ורע - אדם שם לכל יצור חי - אדם וחוה נישאים על ידי ה'.",
  "Genesis 3": "הנחש (לוציפר) מטעה את חוה - היא ואחר כך אדם משתתפים בפרי האסור - זרעה (משיח) יחבור את ראש הנחש - מוסברים תפקידי האישה והאדם - אדם וחוה מגורשים מגן העדן - אדם מנחה - חוה הופכת לאם כל החיים.",
  "Genesis 4": "חוה נושאת את קין והבל - הם מקריבים קורבנות - קין הורג את הבל ומקולל על ידי ה', שגם שם עליו חותם - בני האדם מתרבים - אדם מוליד את סט, ושת מוליד את אנוס.",
  "Genesis 5": "דורותיו של אדם הם אדם, שת, אנוס, קינן, מהללאל, ג'ארד, חנוך (שהלך עם אלוהים), מתושלח, למך ונוח (שהוליד את שם, חם ויפת).",
  "Genesis 6": "בני אלוהים מתחתנים עם בנות האדם - בני אדם פונים לרשע, הארץ מלאה באלימות, וכל בשר מושחת - המבול מובטח - אלוהים מקים את בריתו עם נח, הבונה תיבה כדי להציל את משפחתו וחיות שונות.",
  "Genesis 7": "משפחתו של נח וחיות ועופות שונים נכנסים לתיבה - המבול בא, והמים מכסים את כל הארץ - כל שאר החיים הנושמים מושמדים.",
  "Genesis 8": "המבול נפסק - נח שולח יונה, שחוזרת עם עלה של זית - הוא משחרר את כל היצורים החיים מהתיבה - הוא מקריב קורבנות - מובטחים זמן זריעה, קציר ועונות.",
  "Genesis 9": "נח ובניו מצווים להתרבות ולמלא את הארץ - ניתן להם שליטה על כל צורות החיים - עונש מוות נגזר על רצח - אלוהים לא ישמיד את הארץ שוב במבול - כנען מקולל; שם ויפת מבורכים.",
  "Genesis 10": "צאצאיו של נח הם יפת, שצאצאיו הם גויים; חם, שבין צאצאיו הכנענים; ושם, שממנו יצא פלג (שבימיו נחלקה הארץ).",
  "Genesis 11": "כל הגברים מדברים באותה שפה - הם בונים את מגדל בבל - ה' מבלבל את שפתם ומפזר אותם על כל הארץ - הדורות של שם כוללים את אברם, שאשתו היא שרי - אברם עוזב את אור ומתיישב בחרן.",
  "Genesis 12": "אברם יהפוך לעם גדול - הוא וזרעו יברך את כל משפחות הארץ - הוא נוסע מחרן לארץ כנען - בגלל הרעב הוא יורד למצרים - אברם ושרי נבחנים בחצר פרעה.",
  "Genesis 13": "אברם חוזר ממצרים - הוא ולוט נפרדים - ה' יעשה את זרעו של אברם כעפר הארץ במספר - אברם מתיישב בחברון.",
  "Genesis 14": "לוט נלכד בקרבות המלכים - הוא נחלץ על ידי אברם - מלכיצדק נותן לחם ויין ומברך את אברם - אברם משלם מעשר - הוא מסרב לקבל את שלל הכיבוש.",
  "Genesis 15": "אברם חפץ בצאצאים - ה' מבטיח לו זרע במספר ככוכבים - אברם מאמין בהבטחה - זרעו יהיו זרים במצרים - ואז, לאחר ארבעה דורות, הם יירשו את כנען.",
  "Genesis 16": "שרי נותן את הגר לאברם כאשתו-הגר בורחת משראי-מלאך מצווה על הגר לחזור ולהיכנע לשראי-הגר נושאת את ישמעאל.",
  "Genesis 17": "אברם מצווה להיות מושלם - הוא יהיה אב לגויים רבים - שמו שונה לאברהם - ה' כורת ברית להיות אלוהים לאברהם ולזרעו לנצח - כמו כן, ה' נותן לאברהם את ארץ כנען לנחלת עולם - ברית המילה הופכת לאות הברית הנצחית בין אלוהים לאברהם - ישתנה שמו של ה' עם שרה, שמו של ה' ישרע. ברית - אברהם ואנשי ביתו נימולים.",
  "Genesis 18": "אברהם מארח שלושה אנשים קדושים - הם מבטיחים שלשרה יהיה בן - אברהם יצווה על ילדיו להיות צודקים - ה' מופיע אליו - הם דנים על חורבן סדום ועמורה.",
  "Genesis 19": "לוט מארח אנשים קדושים - אנשי סדום מבקשים להתעלל באורחיו של לוט ונפגעים בעיוורון - לוט נשלח מסדום - ה' ממטיר גפרית ואש על סדום ועמורה - בנות לוט שומרות על זרעו בארץ.",
  "Genesis 20": "אבימלך חפץ בשרה, שנשמרת על ידי ה' - אברהם מתפלל על אבימלך, וה' מברך אותו ואת בני ביתו.",
  "Genesis 21": "שרה נושאת את יצחק - הוא נימול - הגר ובנה מגורשים מבית אברהם - ה' מציל את הגר וישמעאל - אברהם ואבימלך מתמודדים בכבוד זה עם זה.",
  "Genesis 22": "אברהם מצווה להקריב את יצחק, בנו - גם האב וגם הבן נכנעים לרצון ה' - זרעו של אברהם יהיה ככוכבים והחול במספר - בזרעו יתברכו כל העמים - רבקה נולדה לבתואל.",
  "Genesis 23": "שרה מתה ונקברת במערת המכפלה, אותה קונה אברהם מעפרון החתי.",
  "Genesis 24": "אברהם מצווה שיצחק לא יתחתן עם כנעני - ה' מדריך את משרתו של אברהם בבחירת רבקה כאישה ליצחק - רבקה בורכה להיות אם לאלפי מיליונים - היא מתחתנת עם יצחק.",
  "Genesis 25": "אברהם מתחתן, יש לו צאצאים, מת ונקבר במערת המכפלה - צאצאיו דרך ישמעאל רשומים - רבקה מתעברת, ויעקב ועשיו נאבקים בבטנה - ה' מגלה את גורלם לרבקה - עשיו מוכר את הבכורה שלו תמורת בלגן של בשר.",
  "Genesis 26": "ה' מבטיח ליצחק את הדורות הבאים ככוכבי שמים במספר - בזרעו יתברכו כל העמים - ה' משגשג ביצחק, בזמני וברוחני, למען אברהם - יצחק מקריב קורבנות - עשו מתחתן עם נשים חיתיות לצער הוריו.",
  "Genesis 27": "רבקה מדריכה את יעקב בחיפוש ברכות - יעקב יתברך שהוא בעל שליטה ושלטון בעמים ובעמים - עשיו שונא את יעקב ומתכנן להרוג אותו - רבקה חוששת שיעקב יינשא לאחת מבנות חת.",
  "Genesis 28": "יצחק אוסר על יעקב להתחתן עם כנעני - הוא מברך את יעקב וזרעו בברכות אברהם - עשיו מתחתן עם בת ישמעאל - יעקב רואה בחזון סולם מגיע עד השמים - ה' מבטיח לו זרע כעפר הארץ במספר - ה' גם מבטיח ליעקב כי בו ובזרעו יבורכו כל משפחות יקוב - יברך בו ובזרעו יברך.",
  "Genesis 29": "יעקב פוגש את רחל בבאר - הוא משרת את לבן שבע שנים עבורה - לבן נותן ליעקב תחילה את לאה ולאחר מכן את רחל בנישואים - יעקב משרת שבע שנים נוספות - לאה נושאת את ראובן, שמעון, לוי ויהודה.",
  "Genesis 30": "יעקב מתחתן עם בלהה, והיא יולדת את דן ונפתלי - הוא נושא את זילפה, והיא יולדת את גד ואשר - לאה יולדת את יששכר וזבולון ובת, דינה - ואז רחל הרה ויולדת את יוסף - יעקב עובד אצל לבן בשכר בקר וצאן.",
  "Genesis 31": "ה' מצווה על יעקב לשוב לכנען, ויעקב מסתלק בסתר - לבן רודף אחריו; הם פותרים את המחלוקות ביניהם וכורתים ברית שלום - לבן מברך את צאצאיו, והוא ויעקב נפרדים.",
  "Genesis 32": "יעקב רואה מלאכים - הוא מבקש מאלוהים שישמור אותו מפני עשיו, לו הוא מכין מתנות - הוא נאבק כל הלילה עם שליח אלוהים - שמו של יעקב משתנה לישראל - הוא רואה את אלוהים פנים אל פנים.",
  "Genesis 33": "יעקב ועשיו נפגשים ומתפייסים - עשיו מקבל את המתנות של יעקב - יעקב מתיישב בכנען, שם הוא בונה מזבח.",
  "Genesis 34": "שכם מטמא את דינה - החוים מבקשים לסדר נישואים עם משפחתו של יעקב - רבים, לאחר שנימולו, נהרגים על ידי שמעון ולוי - יעקב מוכיח את בניו.",
  "Genesis 35": "הקב\"ה שולח את יעקב לבית אל, שם הוא בונה מזבח וה' נגלה אליו - אלוהים מחדש את ההבטחה שיעקב יהיה עם גדול וששמו יהיה ישראל - יעקב מקים מזבח ומוזג קרבן משקה - רחל נושאת את בנימין, מתה בלידה, ונקברת ליד בית לחם - ראובן חוטאת עם בלהה ואישאוש - ראובן חוטאת עם בלהה וע\"ש.",
  "Genesis 36": "צאצאיו של עשו, שהוא אדום, רשומים.",
  "Genesis 37": "יעקב אוהב ומעדיף את יוסף, השנוא על אחיו - יוסף חולם שהוריו ואחיו מתנשאים לו - אחיו מוכרים אותו למצרים.",
  "Genesis 38": "ליהודה יש ​​שלושה בנים מאישה כנענית - ער ואונן נהרגים בידי ה' - תמר, מחופשת לזונה, יולדת תאומים על ידי יהודה.",
  "Genesis 39": "יוסף, ששגשג על ידי ה', הופך לשליט בביתו של פוטיפר - הוא מתנגד להתקדמות אשת פוטיפר, הואשם שווא, ומושלך לכלא - שומר הכלא מעביר את ענייני הכלא לידיו של יוסף.",
  "Genesis 40": "יוסף מפרש את חלומותיו של המשרת הראשי והאופה הראשי של פרעה - המשרת אינו מצליח לספר לפרעה על יוסף.",
  "Genesis 41": "פרעה חולם על הבקר ועל אוזני התבואה - יוסף מפרש את החלומות כשבע שנים של שפע ושבע של רעב - הוא מציע תוכנית אחסון תבואה - פרעה מכין אותו לשליט כל מצרים - יוסף מתחתן עם אסנת - הוא אוסף תבואה כחול על שפת הים - אסנת נושא את מנשה וגרעינים למצריים ולמצרי אפרים אחרים.",
  "Genesis 42": "יעקב שולח את בניו לקנות תבואה במצרים - הם משתחוים לפני יוסף - הוא מטיל נגדם האשמות קשות, כולא את שמעון ושולח אותם בחזרה לבנימין.",
  "Genesis 43": "יעקב משתכנע לשלוח את בנימין למצרים - אחיו של יוסף מכבדים אותו - כולם אוכלים ושותים ביחד.",
  "Genesis 44": "יוסף מסדר לעצור את חזרת אחיו לכנען - יהודה מציע את עצמו במקום בנימין למען אביהם.",
  "Genesis 45": "יוסף מתוודע לאחיו - הם שמחים יחד - פרעה מזמין את יעקב ומשפחתו לשבת במצרים ולאכול את שומן הארץ.",
  "Genesis 46": "ה' שולח את יעקב ומשפחתו בת שבעים נפש למצרים - צאצאיו של יעקב נקראים - יוסף פוגש את יעקב.",
  "Genesis 47": "בני ישראל מתיישבים בגושן - יעקב מברך את פרעה - יוסף מוכר תבואה למצרים - פרעה מקבל את הבקר והאדמות של המצרים - יעקב רוצה להיקבר עם אבותיו בכנען.",
  "Genesis 48": "יעקב מספר על הופעת ה' אליו בלוז - הוא מאמץ את אפרים ומנשה כילדיו - יעקב מברך את יוסף - הוא שם את אפרים לפני מנשה - זרע אפרים יהפוך להמון עמים - בני ישראל ישובו לארץ אבותיהם.",
  "Genesis 49": "יעקב מברך את בניו ואת זרעם - ראובן, שמעון ולוי נעזרים - יהודה ישלוט עד שיבוא שילה (המשיח) - יוסף הוא ענף פורה ליד באר - ענפיו (הנפים והלמנים) ידרסו את החומה - הרועה והאבן של ישראל (המשיח) יברך את יוסף יקבור בזמני וברוחני את יוסף באביו - יכול להיקבר באביו. מוסר את רוח הרפאים ונאסף אל עמו.",
  "Genesis 50": "גופתו של יעקב נחנטת - יוסף קובר אותו בכנען - יוסף מנחם את אחיו - בני ישראל מתרבים - יוסף מבטיח שאלוהים יוציא את ישראל ממצרים לכנען - יוסף מת במצרים ונחנט.",
  "Exodus 1": "בני ישראל מתרבים - הם נעבדים על ידי המצרים - פרעה מבקש להשמיד את הבנים שנולדו לנשים עבריות.",
  "Exodus 2": "משה נולד להורים לוויים, גדל על ידי בת פרעה, הורג מצרי להגנתו של ישראל, בורח למדיין ומתחתן עם ציפורה - ישראל בשעבוד זועק לאלוהים.",
  "Exodus 3": "ה' מופיע למשה ליד הסנה הבוער - משה נקרא לחלץ את ישראל משעבוד - ה' מזהה את עצמו כאלוהי אברהם, יצחק ויעקב, וכגדול אני - הוא מבטיח להכות את מצרים ולהוציא את עמו בעושר רב.",
  "Exodus 4": "ה' נותן אותות למשה - אהרון נבחר כדובר - ישראל היא בכור ה' ויש לשחררו כדי לשרת אותו - בנו של משה נימול - משה ואהרן מובילים את ישראל בפולחן.",
  "Exodus 5": "משה ואהרון מבקשים מפרעה לשחרר את ישראל - פרעה משיב, מי ה'? - הוא מטיל עול גדול יותר על בני ישראל.",
  "Exodus 6": "יהוה מזהה את עצמו כיהוה - יוחסין של ראובן, שמעון ולוי רשומים.",
  "Exodus 7": "משה מונה לתת את דבר ה' לפרעה - ה' ירבה אותות ומופתים במצרים - מטה אהרן הופך לנחש - הנהר הופך לדם - הקוסמים מחקים את ניסים של משה ואהרון.",
  "Exodus 8": "ה' שולח מכות צפרדעים, כינים וזבובים על מצרים - פרעה מקשה את לבו.",
  "Exodus 9": "ה' משמיד את בהמת המצרים, אבל לא של בני ישראל - שחין ובלילים נשלחים על המצרים - ה' שולח ברד ואש על עם פרעה, אבל לא על עם ישראל.",
  "Exodus 10": "ה' שולח מכת ארבה - ואחריה חושך סמיך בכל מצרים במשך שלושה ימים - משה נגרש מפני פרעה.",
  "Exodus 11": "בני ישראל היוצאים מורשים לבקש תכשיטים וזהב משכניהם - ה' מבטיח להרוג את הבכורים בכל בית מצרי - הוא שם הבדל בין המצרים לבני ישראל.",
  "Exodus 12": "ה' מכין את הפסח ואת חג המצות - כבשים ללא רבב נהרגים - ישראל ניצלת בדמם - בכור מכל המצרים נהרג - ישראל נדחפת ממצרים לאחר 430 שנה - אין לשבור עצמות של כבשי הפסח.",
  "Exodus 13": "יש לקדש את בכורי האדם והבהמה לה' - חג המצות יערוך בארץ כנען - משה מוציא את עצמות יוסף ממצרים - ה' שומר על ישראל בעמוד ענן ביום ובעמוד אש בלילה.",
  "Exodus 14": "ישראל יוצאת ממצרים - ישראל עוברת בים סוף על אדמה יבשה - ה' מפיל את המצרים בתוך הים.",
  "Exodus 15": "בני ישראל שרים את שירו ​​של משה - משבחים את ה' כאיש מלחמה ושמחים בהצלתם ממצרים - מימי מרה נרפאים - ה' מבטיח לשחרר את ישראל ממחלות מצרים.",
  "Exodus 16": "ישראל ממלמלים מחוסר לחם ותאוות בשר מצרים - ה' ממטיר לחם מן השמים ושולח שליו לבשר - נותנים לישראל המן בכל יום, מלבד השבת, במשך ארבעים שנה.",
  "Exodus 17": "ישראל ממלמלים מחוסר מים - משה מכה סלע בחורב, ומים זורמים החוצה - אהרון וחור מחזיקים את ידיו של משה כך שיהושע ינצח בעמלק.",
  "Exodus 18": "יתרו מגיע אל משה מביא את אשת משה ובניו ומקריב קורבנות ליהוה - משה יושב על כיסא הדין ושומע את כל התיקים - יתרו מייעץ למשה ללמד את החוק, למנות שופטים פחותים ולהאציל להם סמכות.",
  "Exodus 19": "ה' כורת ברית להפוך את ישראל לאוצר מיוחד, ממלכת כוהנים וגוי קדוש - העם מתקדש - ה' מופיע על סיני בין אש, עשן ורעידות אדמה.",
  "Exodus 20": "ה' מגלה את עשרת הדיברות - ישראל תעיד שה' דיבר משמים - אסור לבני ישראל לעשות אלים מכסף וזהב - עליהם להרכיב מזבחות של אבנים לא חצובות ולהקריב עליהם קורבן לה'.",
  "Exodus 21": "ה' מגלה את חוקיו הנוגעים למשרתים, נישואין, עונש מוות על עבירות שונות, מתן עין בעין ושן בשן, והנזק שנגרם על ידי שוורים.",
  "Exodus 22": "ה' מגלה את חוקיו הנוגעים לגניבה, הרס באש, טיפול ברכושם של אחרים, הלוואות, מעשי רחמים, זבחים לאלי שקר, צער אלמנות, ריבית, גנאי אלוהים, ובכורי בני אדם ובעלי חיים - אנשי ישראל מצווים להיות קדושים.",
  "Exodus 23": "יהוה מגלה את חוקיו הנוגעים ליושרה והתנהגות אלוהית - הארץ תנוח בשנת שבתון - בני ישראל יערכו שלושה חגים שנתיים - מלאך, הנושא את שם ה', ידריך אותם - מחלה תוסר - אומות כנען ייגרשו בהדרגה.",
  "Exodus 24": "ישראל מקבלים את דבר ה' בברית - משה מפזר את דם הברית - הוא, אהרן, נדב, אביהוא ושבעים מזקני ישראל רואים את אלוהים - ה' קורא למשה להר לקבל את לוחות האבן והמצוות.",
  "Exodus 25": "ישראל מצווה לתרום רכוש ולבנות משכן, ארון העדות (עם הכפורת והכרובים), שולחן (ללחם הפנים) והפמוט, הכל לפי הדוגמאות שהוצגו למשה בהר.",
  "Exodus 26": "המשכן אמור להיבנות בעשרה וילונות ובקרשים - פרוכת היא להפריד בין הקודש למקום הקדוש ביותר - את ארון העדות (עם הכפפה) יש לשים במקום הקדוש ביותר.",
  "Exodus 27": "המשכן אמור להכיל מזבח לעולה וחצר מוקפת עמודים - אור יישרף תמיד במשכן מועד.",
  "Exodus 28": "את אהרון ובניו יש לקדש ולמשוח לשרת בכהונת הכוהן - בגדיו של אהרן יכללו חושן, אפוד, חלוק, מעיל, מצנפת וחגורה - החושן של המשפט יכיל שתים עשרה אבנים יקרות עם שמות השבטים של ישראל ונושאים שם השבטים. חושן.",
  "Exodus 29": "את אהרון ובניו יש לרחוץ, למשוח ולהתקדש - יש לערוך טקסי קורבנות שונים - לכפר על חטאי העם - ה' מבטיח לשכון בתוכם.",
  "Exodus 30": "יש להניח מזבח קטורת לפני הפרוכת - כפרה בדם קרבן החטאת - יש לשלם דמי כפרה כדי לפדות כל זכר - כוהנים צריכים להשתמש בשמן משחת קודש ובבושם.",
  "Exodus 31": "בעלי מלאכה מקבלים השראה בבניית המשכן ובריהוט - ישראל מצווה לשמור את שבתות ה' - גזר דין מוות על חילול שבת - משה מקבל את לוחות האבן.",
  "Exodus 32": "אהרון עושה עגל זהב, שישראל סוגדים לו - משה משמש כמתווך בין ה' לישראל המורדים - משה שובר את לוחות האבן - הלויים הורגים כ-3,000 מורדים - משה מתחנן ומתערב למען העם.",
  "Exodus 33": "ה' מבטיח להיות עם ישראל ולגרש את עם הארץ - אוהל מועד מורחק מהמחנה - ה' מדבר אל משה פנים אל פנים במשכן - מאוחר יותר משה רואה את כבוד ה' אך לא את פניו.",
  "Exodus 34": "משה חוצב לוחות אבן חדשים - הוא עולה להר סיני במשך ארבעים יום - ה' מכריז את שמו ותכונותיו ומגלה את תורתו - הוא כורת ברית נוספת עם ישראל - עור פניו של משה מאיר, והוא עוטה צעיף.",
  "Exodus 35": "ישראל זוכה לשמור את השבת - מתנות חינם מוצעות למשכן - הקריאות וההשראה של אומנים מסוימים מאושרות.",
  "Exodus 36": "אנשים חכמי לב נבחרים לעבוד על המשכן - משה מונע מהעם לתרום חומר נוסף.",
  "Exodus 37": "בצלאל עושה את הארון, את הכפורת ואת הכרובים - הוא עושה את השולחן, את הכלים, את הפמוט, את מזבח הקטורת, את שמן המשחה הקדוש ואת הקטורת המתוקה.",
  "Exodus 38": "בצלאל ואחרים עושים את מזבח העולה ואת כל הדברים הקשורים למשכן - מקריבים 603,550 איש.",
  "Exodus 39": "מכינים בגדי קודש לאהרן ולכהנים - החושן נעשה - גמור אוהל מועד - משה מברך את העם.",
  "Exodus 40": "מגדלים את המשכן - אהרן ובניו נשטפים ומשוחים ונותנים להם כהונת עולם - כבוד ה' ממלא את המשכן - ענן מכסה את המשכן ביום, ואש נחה עליו בלילה.",
  "Leviticus 1": "בעלי חיים ללא רבב מקריבים ככפרה על חטאים - עופות הן ריח מתוק לה'.",
  "Leviticus 2": "איך עושים קרבנות של קמח עם שמן וקטורת.",
  "Leviticus 3": "מקריבים קורבנות שלום עם חיות ללא רבב, שדמם זורק על המזבח - אסור לישראל לאכול שומן ודם.",
  "Leviticus 4": "חוטאים נסלחים באמצעות קורבנות חטאים של בעלי חיים ללא רבב - הכוהנים מכפרים בכך על חטאי העם.",
  "Leviticus 5": "העם צריך להתוודות ולתקן על חטאיו - הסליחה באה באמצעות קרבן גבול - הכוהנים מכפרים על החטא.",
  "Leviticus 6": "העם צריך תחילה לעשות פיצוי על חטא, ואז להקריב מנחת גבול, ובכך לזכות בסליחה באמצעות כפרה על ידי הכוהנים.",
  "Leviticus 7": "רשומים חוקים המסדירים קורבנות שונים - אסור לבני ישראל לאכול שומן או דם - הם סוגדים בהקרבה - באמצעות הקרבה הם זוכים למחילה, נדרים, מקדשים את רכושם, מודים ומתפייסים עם ה'.",
  "Leviticus 8": "אהרון ובניו נשטפים, נמשחים, מתלבשים בבגדי הכהונה שלהם ומקודשים בפני כל ישראל - משה ואהרן מקריבים קורבנות כדי לעשות פיוס וכפרה עם ה'.",
  "Leviticus 9": "אהרון עושה כפרה בקורבן לעצמו ולכל ישראל - הוא ובניו מקריבים קורבנות - כבוד ה' נגלה לכולם - אש מה' מכלה את המנחות על המזבח.",
  "Leviticus 10": "נדב ואביהוא מקריבים קורבנות לא מורשים ונהרגים באש מאת ה' - אסור לאהרן ולבניו האחרים להתאבל עליהם - אהרן ובניו צריכים להימנע מיין ומשקה חזק - עליהם ללמד את כל מה שגילה ה' למשה.",
  "Leviticus 11": "ה' מגלה אילו יצורים חיים מותר ואסור לאכול, ואיזה דברים נקיים וטמאים - הוא מצווה על ישראל: קדושים תהיו כי קדוש אני.",
  "Leviticus 12": "ה' מגלה את חוק טיהור הנשים לאחר הלידה, כולל קרבן חטאת.",
  "Leviticus 13": "חוקים ואסימונים מתגלים להבחנה ושליטה בצרעת - בגדי צרעת יש לשרוף.",
  "Leviticus 14": "חוקים, טקסים וקרבנות מתגלים לניקוי מצורעים, בגדיהם ובתי מצורעים.",
  "Leviticus 15": "מתגלים חוקים, טקסים וקרבנות לניקוי מי שיש לו הפרשה ושאר סוגי טומאה.",
  "Leviticus 16": "איך ומתי על אהרון להיכנס למקום הקדוש מוסבר - מקריבים קורבנות לפייס ישראל עם ה' - השעיר לעזאזל נושא את חטאי העם - חטאי כל ישראל נמחלים ביום הכיפורים.",
  "Leviticus 17": "יש להקריב קורבנות רק לה' במשכן מועד - אסור לישראל להקריב לשדים - כל אכילת דם אסורה - שפיכת דם נדרשת לכפרת חטאים.",
  "Leviticus 18": "ישראל לא יחיו כמו המצרים והכנענים - נישואים להרבה קרובים ואחרים אסורים - התנהגות הומוסקסואלית וסטיות מיניות אחרות הן תועבה - הארץ מגרשת את העמים הנוהגים בתועבות מיניות.",
  "Leviticus 19": "ישראל מצווה: היה קדוש, חי בצדק, אהבת לרעך ושמור את המצוות - ה' מגלה ומאשר מחדש חוקים ומצוות שונים - קסמים, קוסמות, זנות וכל מעשי רע אסורים.",
  "Leviticus 20": "עונש מוות נקבע על הקרבת ילדים למולך, קללת אב ואם, ניאוף, התנהגות הומוסקסואלית, חיות, רוחניות ותועבות אחרות - חוקים ופקודות שונים מפורטים.",
  "Leviticus 21": "הכוהנים צריכים להיות קדושים - הכהן הגדול לא יתחתן עם אלמנה, גרוש או זונה - אסור לצאצאי אהרון עם פגמים פיזיים להקריב את לחם האלוהים על המזבח.",
  "Leviticus 22": "אלו מהכוהנים ובני משפחותיהם שעשויים לאכול מהדברים הקדושים מתוארים - חיות הקורבנות צריכות להיות מושלמות וללא פגמים.",
  "Leviticus 23": "ישראל אמורה לקיים כינוס קדוש בכל שבת שבועית - ישראל תקיים את חגי הפסח, המצות, חג השבועות או הביכורים, החצוצרות, יום הכיפורים והסוכות.",
  "Leviticus 24": "אש תמידית היא לבעור מחוץ לצעיף במשכן - מגדף מוות בסקילה - חוק ישראל הוא אחד של עין תחת עין ושן תחת שן.",
  "Leviticus 25": "כל שנה שביעית יש לשמור כשנת שבתון - כל שנת חמישים תהיה שנה של יובל, שבה מכריזים על החירות בכל הארץ - מתגלים חוקים למכירה ופדיון של קרקעות, בתים ועבדים - הארץ היא של ה', כמו גם המשרתים - הריבית אסורה.",
  "Leviticus 26": "ברכות זמניות ורוחניות ירבו בישראל אם העם יקיים את המצוות - קללה, מלקה ושממה יהיו להם אם יסרבו לה' - כאשר עמו יחזרו בתשובה, ה' ירחם עליהם.",
  "Leviticus 27": "מבואר כיצד מתקדשים נכסים לה' - מצווה על ישראל לשלם מעשר מיבולם, צאן ובקרם.",
  "Numbers 1": "משה והנסיכים בישראל מונים מכל שבט (חוץ מלוי) את אותם זכרים בני עשרים שנה ומעלה - סך הכל 603,550 - הלויים מתמנים להשתתף במשכן.",
  "Numbers 2": "ניתנים הסדר ומנהיגי שבטי וצבאות ישראל באוהליהם.",
  "Numbers 3": "אהרון ובניו משרתים את הכהן - הלויים נבחרים לעבוד במשכן - הם של ה', מחליפים את הבכורים מכל משפחות ישראל - מספרם, תפקידם ושירותם ניתנים.",
  "Numbers 4": "כאשר מחנות ישראל נעים, אהרן ובניו מכסים את הקדשים במשכן - הלויים ממשפחות קהת, גרשון ומררי נושאים את משא המשכן.",
  "Numbers 5": "מצורעים מוציאים מהמחנה - על החוטאים להתוודות ולעשות פיצויים כדי לזכות בסליחה - נשים שלדעתן אינן מוסריות עוברות משפט קנאה בפני הכוהנים.",
  "Numbers 6": "מבואר דין הנזרי, לפיו יכולים בני ישראל להתקדש לה' בנדר - אין שותים יין ומשקה חזק ואם נטמאים חייבים לגלח את ראשם - ה' מגלה את הברכה שתשמש את אהרן ובניו בברכת ישראל.",
  "Numbers 7": "שרי ישראל מקריבים קרבנות למשכן בחנוכתו - ה' מדבר אל משה מכפורת הרחמים, בין הכרובים, על הארון.",
  "Numbers 8": "הלויים נשטפים, מקודשים ומופרדים בנטילת יד - הם של ה' במקום בכורי כל משפחה - הם מתנה לאהרן ולבניו לעשות את עבודת המשכן.",
  "Numbers 9": "ישראל מצווים שוב לקיים את הפסח - ענן מונח על המשכן ביום ובלילה, ועוד אש בלילה - כשנוח הענן, מחנה ישראל; כאשר הוא מתרומם, הם נוסעים.",
  "Numbers 10": "שופרות כסף משמשים לקריאת אספות ולתקיעת אזעקות - הענן נלקח מהמשכן, ובני ישראל צועדים לפי סדרם שנקבע - ארון הברית הולך לפניהם במסעותיהם.",
  "Numbers 11": "אש מאת ה' מכלה את המורדים בישראל - ישראל ממלמלת ומתאווה לבשר במקום המן - משה מתלונן שאינו יכול לשאת בעול לבד - מצווה לבחור שבעים זקנים שיסייעו לו - ה' מבטיח בשר עד שיהפוך לנתעב לבני ישראל - שבעים הזקנים נבחרים, הם מתנבאים, הם מתנבאים, יורדים, ה' יורד במחנה ואלעדרה - יורד ה'. מסופק בשליו - העם מתאוה, מגפה גדולה באה בעקבותיו, ורבים מתים.",
  "Numbers 12": "אהרון ומרים מתלוננים על משה, הענווה מכל האנשים - ה' מבטיח לדבר אל משה מפה אל פה ולגלות לו את דמותו של ה' - מרים הופכת לצרעת למשך שבוע.",
  "Numbers 13": "משה שולח שנים עשר מרגלים לחקור את ארץ כנען - עשרה מהם מביאים דיווח מרושע, מספרים רק על כוחם של התושבים.",
  "Numbers 14": "ישראל ממלמלים ומדברים על חזרה למצרים - יהושע וכלב מודיעים טוב על כנען - משה מתווך בין ישראל ליהוה - בוגרי ישראל לא ייכנסו לארץ המובטחת - ה' הורג את מרגלי השקר במגפה - יש מורדים שמנסים ללכת לבדם ונהרגים על ידי העמלקים והכנענים.",
  "Numbers 15": "פקודות קורבנות שונות מביאות מחילה לישראל חוזרים בתשובה - החוטאים בכוונה מנותקים מקרב העם - נסקלים אדם על איסוף מקלות ביום השבת - בני ישראל צריכים להסתכל בשולי בגדיהם ולזכור את המצוות.",
  "Numbers 16": "קורח, דתן, אבירם ו-250 מנהיגים מורדים ומחפשים משרות כוהנות - האדמה בולעת את שלושת המורדים ואת משפחותיהם - אש מאת ה' מכלה את 250 המורדים - ישראל ממלמלת נגד משה ואהרון על הריגת העם - ה' שולח מגפה, ממנה מתים 14,700.",
  "Numbers 17": "כמבחן, מוט לכל שבט מונח במשכן העדים - מוטו של אהרון ניצנים ופורחים ומוציאים שקדים - הוא נשמר כאות נגד מורדים.",
  "Numbers 18": "אהרון ובניו נקראים לשרת בכהונה - הלויים נקראים לשרת בעבודת המשכן - הלויים אינם מקבלים נחלת אדמה אלא נתמכים במעשרות העם.",
  "Numbers 19": "ניתנים הנחיות להקרבת פרה אדומה - מי הפרדה משמשים לטיהור מחטא - טמאים טמאים זורקים במי הפרדה.",
  "Numbers 20": "מרים מתה - משה מכה סלע במריבה ומוציא מים - מלך אדום מסרב לתת לישראל לעבור בשלום בארצו - אהרון מת, ואלעזר הופך לכהן הגדול.",
  "Numbers 21": "בני ישראל משמידים את אותם כנענים הנלחמים בהם - בני ישראל נגועים בנחשים לוהטים - משה מרים נחש נחושת להציל את המביטים בו - ישראל מנצחת את האמורי, משמידה את אנשי הבשן וכובשת את אדמותיהם.",
  "Numbers 22": "בלק מציע כסף, בהמה וכבוד גדול לבלעם כדי לקלל את ישראל - ה' אוסר על בלעם לעשות זאת - מלאך מתנגד לבלעם בדרך.",
  "Numbers 23": "ה' מצווה על בלעם לברך את ישראל - כך הוא עושה לאמר מי יכול לספור את עפר יעקב? וכן, מה עשה אלוהים!",
  "Numbers 24": "בלעם רואה בחזון ובנבואות על גורלם של ישראל - הוא מנבא על המשיח: כוכב יצא מיעקב, ושרביט יעלה מישראל.",
  "Numbers 25": "בני ישראל העובדים לאלי שקר נהרגים - פינחס הורג את הנואפים ומפסיק את המגפה - מצווה על ישראל להרגיז את המדיינים שהוליכו אותם.",
  "Numbers 26": "משה ואלעזר מונים את בני ישראל בערבות מואב ליד יריחו - הזכרים בני עשרים שנה ומעלה, למעט הלויים, בסך הכל 601,730 - רק כלב ויהושע נותרו מאלה שנמנו בסיני.",
  "Numbers 27": "מבואר חוק הירושה לבנים, לבנות ולקרובים - משה יראה אך לא יכנס לארץ המובטחת - יהושע נקרא ומופרד להנהיג את ישראל.",
  "Numbers 28": "יש להקריב קורבנות בכל בוקר וערב, בשבת, ביום הראשון של כל חודש, בפסח, בכל יום של חג המצות, ובחג הביכורים.",
  "Numbers 29": "יש להקריב קורבנות במהלך החודש השביעי, לרבות בחג השופרות ובחג הסוכות.",
  "Numbers 30": "יש לקיים נדרים ושבועות - אבות רשאים לפסול נדרים של בנות, ובעלים רשאים לפסול נדרים של נשים.",
  "Numbers 31": "משה שולח 12,000 לוחמים המשמידים את המדיינים - הטרף מתחלק בישראל - אף אחד בצבאות ישראל לא אבוד.",
  "Numbers 32": "ראובן, גד וחצי משבט מנשה מקבלים את נחלותיהם ממזרח לירדן - הם כורתים ברית להצטרף לשבטים אחרים בכיבוש כנען.",
  "Numbers 33": "מסעות ישראל ממצרים לכנען נסקרים - העם מצווה לגרש את יושבי הארץ - כל התושבים שנותרו ירגיזו את ישראל.",
  "Numbers 34": "משה מפרט את גבולות נחלתם של ישראל בכנען וממנה את נסיכי השבטים שיחלקו את הארץ.",
  "Numbers 35": "הלויים אמורים להחזיק בערים משלהם - ערי מקלט מוקמות עבור האשמים בהריגה - רוצחים צריכים להיות מוצאים להורג בנקמת דם.",
  "Numbers 36": "חלק מהבנות בישראל מכוונות להתחתן בתוך השבט שלהן - ירושות אסורות לעבור משבט לשבט.",
  "Deuteronomy 1": "משה מתחיל בקריאה של כל מה שפקד את ישראל במשך ארבעים שנה במדבר - בני ישראל מצווים להיכנס לכנען ולרכוש אותם - שופטים ושליטים נבחרים לסייע למשה - מרגלי ישראל מביאים דיווח מרושע - בוגרי ישראל יאבדו - האמורי מביסים את צבאות ישראל.",
  "Deuteronomy 2": "בני ישראל מתקדמים לארצם המובטחת - הם עוברים בשלום בארצות עשו ועמון אך משמידים את האמורי.",
  "Deuteronomy 3": "בני ישראל משמידים את אנשי הבשן - אדמותיהם, במזרח הירדן, ניתנות לראובן ולגד - משה רואה את כנען מפסגה אך הכניסה אליו נמנעת - הוא מייעץ ומחזק את יהושע.",
  "Deuteronomy 4": "משה מאיץ את בני ישראל לקיים את המצוות, ללמדם את בניהם, ולהיות למופת בפני כל העמים - אסור להם לעשות פסלים או לעבוד לאלים אחרים - הם צריכים להעיד כי שמעו את קול ה' - יתפזרו בין כל העמים בעבודתם לאלים אחרים - יתאספו שוב באחרית ימי ה' וברחמים אחר ה'. טוב ה' לישראל.",
  "Deuteronomy 5": "משה מספר על הברית שכרת אלוהים עם ישראל בחורב - הוא סוקר את עשרת הדיברות - שמירת השבת מציינת גם את הגאולה ממצרים - ה' מדבר עם האדם - הברכות נובעות מהציות.",
  "Deuteronomy 6": "משה מכריז, ה' אלוהינו ה' אחד, ואהבת את ה' אלוקיך - בני ישראל מצווים ללמד את בניהם - משה קורא להם לשמור את מצוות ה', עדות וחוקי ה' כדי שיצליחו.",
  "Deuteronomy 7": "ישראל אמורה להשמיד את שבעת אומות כנען - נישואים איתם אסורים פן תגרור כפירה - לישראל יש שליחות כעם קדוש ונבחר - ה' מרחם על האוהבים אותו ושומרים את מצוותיו - הוא מבטיח להסיר מחלה מבני ישראל אם יצייתו.",
  "Deuteronomy 8": "ה' בחן את בני ישראל במדבר ארבעים שנה - אכילת המן לימדה אותם שהאדם חי בדבר ה' - לבושם לא נשחק - ה' ייסר אותם - אם יעבדו אלוהים אחרים, הם יאבדו.",
  "Deuteronomy 9": "עמים אחרים גורשים מכנען בגלל רשעותם - משה חוזר על מרידות ישראל ומספר כיצד תיווך בין העם לבין ה' - בשתי הזדמנויות הלך ללא אוכל ומים במשך ארבעים יום.",
  "Deuteronomy 10": "לוחות האבן המכילים את עשרת הדיברות מונחים בארון - כל מה שאלוהים דורש הוא שישראל יאהבו ויעבדו אותו - כמה גדול ואדיר הוא ה'!",
  "Deuteronomy 11": "תאהב ותשמע את ה' אלוקיך - אם בני ישראל יצייתו, הם יתברכו בגשם וביבול ויגרשנו עמים אדירים - על ישראל ללמוד את חוקי ה' וללמד אותם - הברכות נובעות מהציות; קללות נוכחות באי ציות.",
  "Deuteronomy 12": "ישראל אמורה להשמיד את האלים ואת מקומות הפולחן הכנעניים - ה' יקבע היכן יעבדו עמו - אסור לאכול דם - הפולחן של ישראל חייב להתאים לתקן האלוהי.",
  "Deuteronomy 13": "יהוה בוחן את עמו כדי לראות אם הם יעבדו לאלי שקר - נביאים, חולמים, קרובי משפחה או חברים שדוגלים בפולחן לאלי שקר יומתו - ערי אלילים יושמדו.",
  "Deuteronomy 14": "בני ישראל הם בני ה' יהוה - בהמות טמאות, דגים ועוף אין לאכול - בני ישראל יעשרו את כל גידול זרעם מדי שנה.",
  "Deuteronomy 15": "כל שבע שנים, יש לשחרר את כל החובות - העם זוכה לדאוג לעניים - יש לשחרר משרתים עברים ולתת להם מתנות במהלך השנה השביעית - הזכרים הבכורים של הבקר והעדרים הם של ה'.",
  "Deuteronomy 16": "על ישראל לקיים את הפסח, את חג המצות, את חג השבועות ואת חג הסוכות - כל הזכרים צריכים להופיע מדי שנה לפני ה' בשלושת החגים הללו - אסור לשופטים לעשות משפטים לא הגונים ולא לקחת מתנות.",
  "Deuteronomy 17": "אלה שסוגדים לאלי שקר יומתו - על הכוהנים והשופטים לקבוע את המקרים הקשים - המלכים אינם צריכים לרכוש לעצמם סוסים, נשים או זהב - המלך חייב ללמוד את חוקי אלוהים מדי יום.",
  "Deuteronomy 18": "כיצד תומכים בכוהנים - עתידות, רוחניות וכדומה הם תועבות - נביא (משיח) יקום כמו משה.",
  "Deuteronomy 19": "ערי מקלט מתמנות למקרים של הריגה - רוצחים יומתו - שניים או שלושה עדים נדרשים בתיקי משפט - עדי שקר ייענשו.",
  "Deuteronomy 20": "מתגלים חוקים לבחירת חיילים ולעשיית מלחמה - חיתים, אמורים, כנענים, פריזים, חיוים ויבוסים יושמדו כליל.",
  "Deuteronomy 21": "כיצד מתקנים רציחות על ידי אלמונים - נדרש שוויון בהתמודדות עם נשים וילדים - בנים עקשנים ומרדנים יומתו.",
  "Deuteronomy 22": "משה קובע חוקים הנוגעים לאיבוד רכוש, לבישת בגדים נאותים, דאגה לאינטרסים של אחרים, נישואין עם בתולות ואי מוסריות מינית.",
  "Deuteronomy 23": "משה מפרט את מי רשאי ואסור להיכנס לקהילה - הוא קובע חוקים הנוגעים לתברואה, משרתים, ריבית ונדרים.",
  "Deuteronomy 24": "ניתנים חוקים לגבי גירושין, אנשים שזה עתה נישאו, עשיית סחורה מגברים, לקיחת התחייבויות, צרעת, דיכוי משרתים והשארת הלקטים של יבולים.",
  "Deuteronomy 25": "שופטים קובעים עונש לרשעים - חוק הנישואין קובע לאלמנת אח - נדרשים רק משקלים ומידות - ישראל מצווה למחוק את העמלק מתחת לשמים.",
  "Deuteronomy 26": "בני ישראל צריכים להציע לה' סל בכורות כנען - הם מצווים לשמור את חוק המעשר - הם כורתים ברית לקיים את המצוות, וה' מבטיח לעשות אותם לעם קדוש וגוי גדול.",
  "Deuteronomy 27": "בני ישראל צריכים לעבור את הירדן, לבנות מזבח ולעבוד את ה' - הם העם של ה' אבל יקוללו אם לא ישמעו לו.",
  "Deuteronomy 28": "אם בני ישראל יהיו צייתנים, הם יתברכו בזמני וברוחני - אם הם סוררים, הם יקוללו, יכו ויהרסו; יבואו עליהם מחלות, מגפות ודיכוי; הם ישרתו אלוהי שקר ויהפכו למילת לשון בכל העמים; עמים עזים ישעבדו אותם; וַיֹּאכְלוּ אֶת בְּנֵיהֶם וַיִּפָּזְרוּ בְּכָל הַגּוֹיִם.",
  "Deuteronomy 29": "בני ישראל כורתים ברית עם ה' שבמסגרתה יתברכו אם יצייתו, ויקלל אם יסרבו - אם יסרבו, תהיה ארצם כגופרית ומלח.",
  "Deuteronomy 30": "בני ישראל המפוזרים יאספו מכל העמים כשיזכרו את הברית - משה מניח חיים או מוות, ברכה או קללה, לפני העם.",
  "Deuteronomy 31": "משה מייעץ ליהושע ולכל ישראל להיות חזקים ובאומץ לב - יש לקרוא את התורה לכל ישראל כל שבע שנים - בני ישראל ילכו בעקבות אלוהי שקר וישחיתו.",
  "Deuteronomy 32": "ישירו ישראל את שירו ​​של משה וישבחו: ה' מדבר אל השמים והארץ; בני ישראל היו ידועים בחיי קדם-מוות; אלוהים בחר בהם בחיים האלה; שכחו את סלע ישועתם; שלח אימה, חרב, ונקמה עליהם; אין אלוהים לידו - משה יאסוף אל עמו.",
  "Deuteronomy 33": "משה מברך את שבטי ישראל - לוי יתברך ללמד את משפטי ה' ואת תורתו - יוסף יתברך מכולם; ה' יאסוף את ישראל באחרית הימים - ישראל תנצח.",
  "Deuteronomy 34": "משה רואה את הארץ המובטחת ונלקח על ידי ה' - יהושע מוביל את ישראל - משה היה הנביא הגדול ביותר של ישראל.",
  "Joshua 1": "ה' מדבר אל יהושע - הוא מצווה להיות באומץ טוב, להרהר בתורה ולקיים את המצוות - הוא מכין את ישראל להיכנס לכנען.",
  "Joshua 2": "יהושע שולח מרגלים ליריחו - הם מתקבלים ומוסתרים על ידי רחב - הם מבטיחים לשמור על רחב ובני ביתה.",
  "Joshua 3": "יהושע מוביל את ישראל אל הירדן - ה' כורת את מי הירדן; הוא עומד כערמה, וישראל עוברים על פני אדמה יבשה.",
  "Joshua 4": "יהושע מניח שתים עשרה אבנים להנצחת חציית הירדן - יהושע מוגדל לפני בני ישראל כשהם עוברים את הירדן - לאחר שהכהנים נושאי התיבה עוברים, הנהר חוזר למסלולו.",
  "Joshua 5": "יושבי כנען חוששים מישראל - זכרי ישראל נימולים - ישראל שומרים את הפסח, אוכלים את פרי הארץ והמן נפסק - רב צבא ה' מופיע ליהושע.",
  "Joshua 6": "יריחו נלקחת ונחרבת - רק רחב ובני ביתה ניצלים.",
  "Joshua 7": "ישראל מובסים על ידי אנשי איי - יהושע מתלונן בפני ה' - עכן ובני ביתו נהרסים כי הוא לא ציית ליהוה בלקיחת שלל יריחו.",
  "Joshua 8": "יהושע משתמש במארב, לוקח את עי והורג את יושביו - הוא בונה מזבח בהר עיבל - דברי התורה, גם ברכות וגם קללות, נקראים לעם.",
  "Joshua 9": "הגבעונים במלאכה משיגים ברית עם ישראל - יהושע עושה אותם משרתים לקהילת ישראל.",
  "Joshua 10": "ישראל מביסים את האמורי ובני בריתם, וה' יטיל עליהם אבנים משמים - השמש והירח עומדים במקום - מלכים וערים רבים נחרבים - ה' נלחם למען ישראל.",
  "Joshua 11": "יהושע וישראל כובשים את כל הארץ, הורסים ערים ועמים רבים.",
  "Joshua 12": "שני מלכים במזרח הירדן ושלושים ואחד במערב נכבשים על ידי ישראל.",
  "Joshua 13": "נותרו כמה אדמות שעדיין לא מוחזקות - חלק מהתושבים לא גורשו - נחלות ראובן, גד ומחצית מנשה מאושרות.",
  "Joshua 14": "הארץ מחולקת בהגרלה בין 9½ שבטים - כלב יורש את חברון כפרס מיוחד על נאמנותו.",
  "Joshua 15": "ליהודה ניתנת נחלה בכנען - היבוסים יושבים עם יהודה בירושלים.",
  "Joshua 16": "בני יוסף (אפרים ומנשה) מקבלים את נחלותיהם - חלק מהכנענים ממשיכים לגור בין האפרים.",
  "Joshua 17": "מנשה ואפרים מקבלים שניהם נחלה נוספת - אפרים אמור לגרש את הכנענים מההר.",
  "Joshua 18": "משכן העדה מוקם בשילה - בנימין מקבל ירושה בהגרלה.",
  "Joshua 19": "שמעון, זבולון, יששכר, אשר, נפתלי ודן מקבלים את נחלתם בהגרלה.",
  "Joshua 20": "שש ערי מקלט מתמנות לאשמים בהריגה.",
  "Joshua 21": "הלויים מקבלים ארבעים ושמונה ערים עם פרבריהן - ה' מקיים את כל הבטחותיו ונותן מנוח לישראל.",
  "Joshua 22": "2 וחצי השבטים מודחים בברכה - הם בונים מזבח עדות ליד הירדן כדי להראות שהם עם יהוה - זה לא מזבח לקורבנות או לעולה.",
  "Joshua 23": "יהושע מפציר בישראל לאמץ לב, לקיים את המצוות, לאהוב את ה', ולא להתחתן עם שרידי הכנענים הנשארים בארץ ולא לדבוק בהם - כשבני ישראל יעבדו אלוהים אחרים, הם יקוללו וינושלו.",
  "Joshua 24": "יהושע מדקלם כיצד בירך ה' והנהיג את ישראל - יהושע וכל העם כורתים ברית לבחור בה' ולעבוד אותו בלבד - יהושע ואלעזר מתים - עצמות יוסף, שנלקחו ממצרים, קבורות בשכם.",
  "Judges 1": "יהודה, שמעון ויוסף ממשיכים לכבוש את הכנענים - שרידי הכנענים נותרו בארצות יהודה, מנשה, אפרים, זבולון, אשר, נפתלי ודן.",
  "Judges 2": "מלאך נוזף בישראל על שלא עבדו את ה' - כתבנית לאירועים עתידיים, קם דור חדש שעוזב את ה' ומשרת את הבעל והאשתרות - ה' כועס על בני ישראל ומפסיק לשמור עליהם - הוא מקים שופטים שידריכו ויובילו אותם - הכנענים נשארים בארץ כדי לנסות את ישראל.",
  "Judges 3": "בני ישראל מתערבבים עם הכנענים, עובדים לאלי שקר ומקוללים - עתניאל שופט את בני ישראל - הם משרתים את מואב ונמסרים על ידי אהוד שהורג את עגלון.",
  "Judges 4": "דבורה, נביאה, שופטת את ישראל - היא וברק מצילים את ישראל מהכנענים - יעל, אישה, הורג את סיסרא, הכנעני.",
  "Judges 5": "דבורה וברק שרים שיר הלל כי ישראל נגאלים משעבוד כנעני.",
  "Judges 6": "ישראל עבדים למדיינים - מלאך נגלה לגדעון וקורא לו להציל את ישראל - הוא מפיל את מזבח הבעל, רוח ה' רובצת עליו, וה' נותן לו אות להראות שהוא נקרא להציל את ישראל.",
  "Judges 7": "צבאו של גדעון מצטמצם ל-300 - הם מפחידים את צבאות המדיינים בשופרות ואורות - המדיינים נלחמים ביניהם, בורחים ומובסים על ידי ישראל.",
  "Judges 8": "גדעון רודף ומשמיד את המדיינים - הוא משחרר את בני ישראל אך מסרב להזמנתם למלוך עליהם כמלך - גדעון מת, וישראל חוזרים לעבודת אלילים.",
  "Judges 9": "אבימלך בנו של גדעון מומלך - הוא הורג את שבעים אחיו - יותם מספר אגדה על עצים בוחרים מלך - השכימים זוממים נגד אבימלך - הוא נהרג בתבז.",
  "Judges 10": "טולה ואחר כך יאיר שופטים את ישראל - בני ישראל עובדים לאלי שקר, ננטשים על ידי ה' ונלחמים על ידי אויביהם - הם חוזרים בתשובה ומבקשים מה' ישועה.",
  "Judges 11": "יפת נבחר לקברניט צבאות ישראל - בני עמון מסתערים על ישראל במלחמה - יפת מונחה על ידי הרוח ומביס את עמון בטבח גדול - הוא נודר נדר פזיז, שמוביל להקרבה של בתו היחידה.",
  "Judges 12": "הגלעדים הורגים 42,000 אפרים - יפת, אבזן, אילון ועבדון שופטים כל אחד בתורו את ישראל.",
  "Judges 13": "ישראל נמצאים בעבדות פלשתית ארבעים שנה - מלאך בא אל אשתו של מנוח ומבטיח לבן שיתחיל לחלץ את ישראל - המלאך בא שוב; הוא עולה בלהבה מהמזבח - שמשון נולד, ורוח ה' נעה עליו.",
  "Judges 14": "שמשון הורג אריה צעיר בידיו החשופות - הוא מתחתן עם אשת פלשתים, מציג חידה, מתעתע על ידי אשתו והורג שלושים פלשתים.",
  "Judges 15": "שמשון שורף את תבואת הפלשתים - שורפים את אשתו ואת חותנו - שמשון הורג אלף פלשתים בלח\"י עם עצם לסת של חמור.",
  "Judges 16": "שמשון סוחב את דלתות שער עזה - הוא אוהב את דלילה, שמוסרת אותו לפלשתים - הוא הורס בניין, הורג את עצמו ועוד 3,000 אחרים.",
  "Judges 17": "למיכה יש בית אלים (תמונות) והוא מקדש את הכוהנים שלו.",
  "Judges 18": "הדנים שולחים אנשים לבקש ירושה - הם לוקחים את התמונות והכוהן של מיכה, שורפים את העיר ליש ומקימים עבודת אלילים.",
  "Judges 19": "פילגש של לוי חוזרת לאביה - בעלה לוקח אותה בחזרה, והם לנים בגבעה - אנשי גבעה מתעללים בפילגש והיא מתה - הבעל הלוי חותך אותה לשתים עשרה חלקים ושולח אותם לשבטי ישראל.",
  "Judges 20": "כל ישראל קמים נגד הבנימים, המסרבים למסור את אנשי גבעה - הבנימים נפגעים ומשמדים.",
  "Judges 21": "העם מקונן על חורבן בנימין - תושבי ג'בש-גלעד מושמדים על כך שהם לא משתתפים במלחמה עם בנימין - נשים מסופקות לשארית בנימין.",
  "Ruth 1": "אלימלך ומשפחתו הולכים למואב בגלל רעב - בניו מתחתנים - האב והבנים מתים - רות, המואבית, בעלה שמת, נשארת קבועה לנעמי - הם מגיעים לבית לחם.",
  "Ruth 2": "רות מלקטת בשדות של בועז, קרובת משפחה של נעמי - הוא מתייחס לרות בחביבות.",
  "Ruth 3": "לפי הוראתה של נעמי, רות שוכבת לרגלי בועז - הוא מבטיח כקרוב משפחה לקחת אותה לאשתו.",
  "Ruth 4": "קרוב המשפחה הקרוב מסרב, ובועז לוקח את רות לאישה - רות נושאת את עובד, שדרכו הגיע דוד המלך.",
  "1 Samuel 1": "חנה מתפללת על בן ונשבעה לתת אותו לה' - אלי הכהן מברך אותה - שמואל נולד - חנה משאילה אותו לה'.",
  "1 Samuel 2": "חנה מזמרת לה' - שמואל שר לפני ה' - אלי מברך את אלקנה וחנה, ויש להם בנים ובנות - בני אלי דוחים את ה' וחיים ברשע - ה' דוחה את בית אלי.",
  "1 Samuel 3": "ה' קורא לשמואל - בית אלי לא יטהר בזבחים ומנחות - שמואל מוכר כנביא על ידי כל ישראל - ה' נראה אליו.",
  "1 Samuel 4": "בני ישראל נפגעים ומובסים על ידי הפלשתים, הלוכדים גם את ארון האלוהים - בניו של אלי נהרגים, אלי מת בתאונה, וכלתו מתה בלידה.",
  "1 Samuel 5": "הפלשתים מניחים את הארון בביתו של דגון, אלוהיהם - הפלשתים באשדוד, אחר כך גת, ואחר כך עקרון נפגעים ונהרגים כי הארון שוכן אצלם.",
  "1 Samuel 6": "הפלשתים שולחים בחזרה את הארון עם מנחה - ה' מכה והורג את בני ישראל בבית שמש המביטים לתוך הארון.",
  "1 Samuel 7": "שמואל קורא לישראל לנטוש את אשתרות ואת הבעלים ולעבוד את ה' - ישראל צמים ומבקשים את ה' - הפלשתים נכנעים - שמואל שופט את ישראל.",
  "1 Samuel 8": "בניו של שמואל לוקחים שוחד ומעוותים את הדין - בני ישראל מבקשים מלך שישלוט בהם - שמואל חוזר על טבעו ורעות השלטון המלכותי - ה' מסכים לתת להם מלך.",
  "1 Samuel 9": "שאול, בנו של קיש, בן בנימין, הוא אדם מובחר וטוב - הוא נשלח לחפש את חמוריו של אביו - ה' מגלה לשמואל הרואה ששאול עומד להיות מלך - שאול הולך לשמואל ומתארח אצלו.",
  "1 Samuel 10": "שמואל מושח את שאול להיות רב חובל על נחלתו של ה' - שמואל מפגין את מתנת הצופה - שאול מתנבא בקרב הנביאים, וה' נותן לו לב חדש - הוא נבחר למלך במצפה.",
  "1 Samuel 11": "בני עמון מחנים נגד בני ישראל של ג'בש גלעד - שאול מציל אותם ומביס את בני עמון - מתחדשת מלכותו בגלגל.",
  "1 Samuel 12": "שמואל מעיד על מעשיו הצודקים בישראל - הוא מוכיח את העם על חוסר הכרת הטוב - הוא מפציר בהם לקיים את המצוות פן ישכיל ה' אותם ואת מלכם.",
  "1 Samuel 13": "שאול מקריב קורבן - ה' דוחה אותו ובוחר קברניט אחר על עמו.",
  "1 Samuel 14": "יונתן מכה את חיל המצב של פלשתים - שאול מורה לעם לא לאכול אוכל עד הערב - מבלי לדעת את השבועה, יונתן אוכל, ושאול גוזר על מותו - הוא נחלץ על ידי העם - שאול מציק לאויביו מכל צד.",
  "1 Samuel 15": "שאול מצווה להכות ולהשמיד את העמלק ואת כל מה שיש להם - הוא מציל כמה חיות להקרבה - שאול נדחה כמלך ונאמר לו שעדיף לציית מקרבן - שמואל משמיד את אגג.",
  "1 Samuel 16": "ה' בוחר בדוד מבית לחם למלך - הוא נמשח על ידי שמואל - שאול בוחר בדוד כחברה ונושא נשק.",
  "1 Samuel 17": "ישראל והפלשתים נכנסים למלחמה - גוליית מגת, ענק, מתריס נגד ישראל ומאתגר כל ישראל לקרב אישי - דוד יוצא נגדו בשם ה' - דוד הורג את גוליית בקלע ובאבן - ישראל מנצחת את הפלשתים.",
  "1 Samuel 18": "יהונתן אוהב את דוד - שאול מציב את דוד על צבאותיו - דוד זוכה לכבוד העם, ושאול מקנא - דוד מתחתן עם מיכל בת שאול.",
  "1 Samuel 19": "שאול מבקש להרוג את דוד - מיכל מצילה את דוד בתחבולות - דוד מצטרף לשמואל ולחברת הנביאים.",
  "1 Samuel 20": "דוד ויהונתן כורתים ברית של ידידות ושלום - הם נפרדים זה מזה.",
  "1 Samuel 21": "דוד מקבל עזרה מאחימלך הכהן - הוא אוכל את לחם הפנים - הוא הולך לגת, שם הוא מעמיד פני טירוף.",
  "1 Samuel 22": "דוד זוכה לחסידים - הוא הולך ממקום למקום, בורח מפני שאול - שאול הורג את הכוהנים שעשו חסד עם דוד.",
  "1 Samuel 23": "דוד מכה את הפלשתים ומציל את קעילה - הוא ממשיך לברוח מפני שאול - יונתן מנחם אותו בציפה.",
  "1 Samuel 24": "דוד מוצא את שאול במערה וחוס על חייו - שאול מתוודה שדוד צדיק ממנו - דוד נשבע שלא כרת את זרעו של שאול.",
  "1 Samuel 25": "שמואל מת - נבל דוחה את דוד ומסרב לתת לו אוכל - אביגיל מתערבת, מצילה את נבל ונותנת לדוד מתנה - דוד נרגע, נבל מת ודוד מתחתן עם אביגיל.",
  "1 Samuel 26": "דוד שוב חוסך על חייו של שאול - הוא שוב מסרב להושיט את ידו נגד המשוח של ה' - שאול ודוד נפרדים.",
  "1 Samuel 27": "דוד בורח לאכיש בגת - הוא שוכן בין הפלשתים שישה עשר חודשים.",
  "1 Samuel 28": "שאול שואל את המכשפה מאנדור לגילוי - היא מנבאת את מותו, את מות בניו ואת תבוסת ישראל בידי הפלשתים.",
  "1 Samuel 29": "ישראל והפלשתים מתאספים למלחמה - נסיכי פלשתים שולחים את דוד.",
  "1 Samuel 30": "העמלק מקלקל את ציקלג ואת גבולות יהודה - דוד מכה את עמלק ומחזיר ומחלק את השלל.",
  "1 Samuel 31": "הפלשתים מביסים את ישראל - שאול ושלושת בניו נהרגים - גופותיהם נלקחות על ידי הגלעדים ונשרפות.",
  "2 Samuel 1": "לדוד נודע על מותם של שאול ויהונתן - הוא הורג את העמלקי הטוען שהרג את שאול - דוד מקונן בשירה על לכתם של שאול ויהונתן.",
  "2 Samuel 2": "דוד נמשח למלך על בית יהודה - אישבושת הופך למלך ישראל - חסידיו של דוד מביסים את אבנר ואת אנשי ישראל.",
  "2 Samuel 3": "בתי דוד ושאול מנהלים מלחמה ארוכה - דוד מתחזק - אבנר מצטרף לדוד אך נהרג על ידי יואב - דוד מתאבל על אבנר.",
  "2 Samuel 4": "שניים מהקברניטים של שאול הורגים את אישבושת - הם לוקחים את ראשו אל דוד, אשר הורגים אותם על הריגת צדיק.",
  "2 Samuel 5": "כל ישראל מושחים את דוד למלך - הוא לוקח את ירושלים וברוך ה' - הוא כובש את הפלשתים.",
  "2 Samuel 6": "דוד לוקח את התיבה לעיר דוד - עוזה נפגע על ייצוב התיבה ומת - דוד רוקד לפני ה', וגורם לפריצה בינו לבין מיכל.",
  "2 Samuel 7": "דוד מציע לבנות בית ליהוה - ה', באמצעות נתן, אומר שהוא לא ביקש מדוד לעשות זאת - ה' יקים את ביתו וממלכתו של דוד לנצח - דוד מתפלל תפילת הודיה.",
  "2 Samuel 8": "דוד מביס ומכניע עמים רבים - ה' עמו - הוא עושה משפט ומשפט לכל עמו.",
  "2 Samuel 9": "דוד מבקש לכבד את בית שאול - הוא מוצא את מפיבושת בן יהונתן, לו הוא מחזיר את כל ארץ שאול.",
  "2 Samuel 10": "שליחי דוד עוברים התעללות על ידי העמונים - ישראל מנצחת את העמונים ואת הסורים.",
  "2 Samuel 11": "דוד שוכב עם בת שבע, והיא מתעבר - לאחר מכן הוא מארגן את מותו בקרב בעלה, אוריה.",
  "2 Samuel 12": "נתן מספר לדוד את משל כבש הכבשה - ה' נתן נשים רבות לדוד, שכעת הוא מקולל על כך שלקח את בת שבע - דוד צם ומתפלל עבור בנו, אבל ה' לוקח אותו - שלמה נולד - דוד כובש את עיר המלוכה של בני עמון.",
  "2 Samuel 13": "אמנון חפץ בתמר, אחותו, ומכריח אותה - הוא נהרג בפקודת אבשלום - אבשלום בורח לגשור.",
  "2 Samuel 14": "יואב מסדר באמנות להחזיר את אבשלום הביתה לאחר שלוש שנים - לאחר שנתיים נוספות, אבשלום רואה את המלך, והם מתפייסים.",
  "2 Samuel 15": "אבשלום זומם נגד דוד וזוכה לתמיכת העם - דוד בורח, ואבשלום נכנס לירושלים.",
  "2 Samuel 16": "לכאורה, מפיבושת מבקש להיות מלך - שמעי, מבית שאול, מקלל את דוד - אחיתופל מייעץ לאבשלום, ואבשלום לוקח את פילגשים של אביו.",
  "2 Samuel 17": "עצתו של אחיתופל הופכת על ידי חושי - דוד מוזהר ובורח מעל הירדן - אחיתופל תולה את עצמו - העם מתכונן למלחמה.",
  "2 Samuel 18": "בני ישראל נפגעים ביערות אפרים - יואב הורג את אבשלום - הבשורות על מותו נלקחות לדוד, המתאבל על בנו.",
  "2 Samuel 19": "יואב נוזף בדוד על כך שהעדיף את אויביו במקום חבריו - דוד מחליף את יואב בעמאסה - שמעי, אשר קילל את דוד, זוכה לחנינה - מפיבושת נשבע אמונים לדוד - אנשי יהודה מחזירים את דוד לירושלים.",
  "2 Samuel 20": "שיבא מוביל את שבטי ישראל מדוד - יואב הורג את עמשא ורודף את שיבא - אישה חכמה משתדלת - מות שיבא מסיים את המרד.",
  "2 Samuel 21": "ה' שולח רעב - דוד מבין שהרעב הגיע בגלל ששאול היכה את הגבעונים, בניגוד לשבועת ישראל - דוד מוסר שבעה בני שאול לתלייה על ידי הגבעונים - ישראל והפלשתים ממשיכים במלחמותיהם.",
  "2 Samuel 22": "דוד משבח את ה' במזמור הודיה - ה' הוא מבצרו ומושיעו, הוא גבור וחזק בישועה, הוא גומל לבני אדם על פי צדקתם, רחם על רחמנים, דרכו מושלמת, חי וברוך הוא.",
  "2 Samuel 23": "דוד מדבר בכוחה של רוח הקודש - על השליטים להיות צודקים, לשלוט ביראת אלוהים - שמותיהם של גבוריו של דוד ומעשיהם מושבחים.",
  "2 Samuel 24": "דוד חוטא במספור ישראל ויהודה - אנשי המלחמה בסך הכל 1,300,000 - ה' משמיד 70,000 איש במגפה - דוד רואה מלאך, מקריב קורבן והמגפה נעצרת.",
  "1 Kings 1": "אבישג מוקיר את דוד בגילו המופלג - אדוניה שואף להיות מלך - בת שבע ונתן מייעצים לדוד על מזימתו של אדוניה - דוד שם את שלמה למלך, והוא נמשח על ידי צדוק - מטרתו של אדוניה נכשלת.",
  "1 Kings 2": "דוד מצווה על שלמה לקיים את המצוות וללכת בדרכי ה' - דוד המלך מת ושלמה מלך - אדוניה, יואב ושמעי מומתים, ואביתר נדחה ככוהן גדול - המלכות מתבססת עם שלמה.",
  "1 Kings 3": "שלמה אוהב את ה' ומקיים את מצוותיו - ה' מופיע אל שלמה ומבטיח לו לב חכם ומבין - הוא שופט בין שתי זונות וקובע מי היא אם לילד.",
  "1 Kings 4": "הקצינים בחצר שלמה רשומים - שלמה מושל בשלום ובשגשוג על ממלכה גדולה - חוכמתו והבנתו עולים על זו של כל בני האדם.",
  "1 Kings 5": "שלמה מבקש וזוכה לעזרתו של חירם בהשגת עצים לבניית המקדש - בני ישראל חוצבים אבנים וחותכים עצים לבית המקדש.",
  "1 Kings 6": "שלמה בונה את בית המקדש - ה' מבטיח לגור בין בני ישראל אם הם יצייתו - מתוארים קישוטי המקדש.",
  "1 Kings 7": "שלמה בונה לעצמו בית - חירם מצור עושה את שני העמודים, את הים המותך, את עשרת הבסיסים, את עשרת הכירות ואת כל הכלים לבית המקדש - הים המותך (אגן הטבילה) מונח על גבם של שנים עשר שוורים.",
  "1 Kings 8": "ארון הקודש, המכיל את שני לוחות האבן, מונח בקודש הקדשים - כבוד ה' ממלא את בית המקדש - שלמה נושא את תפילת הקדשה - הוא מבקש ברכות זמניות ורוחניות על ישראל החוזרים בתשובה והמתפללים - העם מקריב ומתפלל במשך ארבעה עשר יום.",
  "1 Kings 9": "ה' שוב מופיע לשלמה - ה' מבטיח ברכות גדולות אם בני ישראל יהיו צייתנים וקללות גדולות אם יעזבו אותו - שלמה שולט בפאר, גובה מס על הלא ישראלים ובונה צי של ספינות.",
  "1 Kings 10": "מלכת שבא מבקרת את שלמה - עושרו וחוכמתו עולים על זה של כל מלכי הארץ.",
  "1 Kings 11": "שלמה מתחתן עם נשים שאינן ישראליות, ונשותיו מפנים את לבו לעבודת אלי שקר - ה' מעורר יריבים נגדו, כולל ירבעם בן נבט - אחיה מבטיח לירבעם שהוא יהיה מלך עשרת השבטים - שלמה מת ורחבעם ממלך במקומו.",
  "1 Kings 12": "רחבעם מבקש להטיל עול גדול יותר על העם - עשרת השבטים מתקוממים ופונים לירבעם - ירבעם פונה לעבודת אלילים וסוגד לאלי שקר.",
  "1 Kings 13": "ירבעם נפגע ולאחר מכן נרפא על ידי נביא מיהודה - הנביא מעביר את המסר שלו, מוליך שולל על ידי נביא מבית אל, ונהרג על ידי אריה בשל אי ציותו - ירבעם ממשיך בפולחן השקר בישראל.",
  "1 Kings 14": "אחיהו מנבא את חורבן ביתו של ירבעם, את מות ילדו ואת פיזור בני ישראל בגלל עבודת האלילים שלהם - ירבעם מת ונדב מלך - יהודה, תחת רחבעם, הופך לרשע - שישק ממצרים לוקח אוצרות מהמקדש - רחבעם מת ורחבעם.",
  "1 Kings 15": "אביעם ממלוך ברשע ואחר כך אסא מלך בצדק ביהודה - נדב ואחר כך בעשא ממלוך ברשע בישראל - בעשא משמיד את בית ירבעם.",
  "1 Kings 16": "יהוא מנבא רעה על בעשא ועל ביתו - אלה, זמרי, עמרי ואחאב מלכים ברשע - זמרי הורס את ביתו של בעשא - אחאב מתחתן עם איזבל, משתחווה לבעל ומכעיס את ה'.",
  "1 Kings 17": "אליהו חותם את השמים והוא ניזון מהעורבים-לפקודתו חבית הקמח וקנקן השמן של אלמנת צרפת לעולם אינם מתרוקנים-הוא מעלה את בנה ממוות.",
  "1 Kings 18": "אליהו נשלח לפגוש את אחאב - עובדיהו מציל מאה נביאים ופוגש את אליהו - אליהו מאתגר את נביאי הבעל להפיל אש מהשמים - הם נכשלים - הוא קורא אש, הורג את נביאי הבעל ופותח את השמים לגשם.",
  "1 Kings 19": "איזבל מחפשת את חייו של אליהו - מלאך שולח אותו אל חורב - ה' מדבר אל אליהו, לא ברוח ולא ברעידת האדמה ולא באש, אלא בקול דומם וקטן - אלישע מצטרף לאליהו.",
  "1 Kings 20": "בן-הדד מסוריה עושה מלחמה עם ישראל - הסורים מובסים פעמיים - אחאב נותן לבנהדד לצאת לחופשי, בניגוד לרצון ה'.",
  "1 Kings 21": "אחאב חפץ בכרם של נבות - איזבל מסדרת עדי שקר, ונבות נסקל בגלל חילול השם - אליהו מנבא שאחאב ואיזבל וביתם ייחרבו.",
  "1 Kings 22": "יהושפט מיהודה ואחאב מישראל מאחדים כוחות נגד סוריה - נביאיו של אחאב מנבאים הצלחה - מיכיה מנבא את תבוסתו ומותו של אחאב - אחאב נהרג וכלבים מלחכים את דמו - יהושפט מושל בצדק ביהודה - אחזיהו מלך בישראל ומשרת את הבעל.",
  "2 Kings 1": "אחזיהו פונה לבעל זבוב כדי ללמוד אם יחיה - אליהו מנבא את מותו של אחזיהו - אליהו קורא אש מהשמים כדי לכבות את החיילים שנשלחו לתפוס אותו.",
  "2 Kings 2": "אלישע והנביאים יודעים שאליהו מתורגם - אליהו מחלק את מי הירדן ונלקח לגן עדן במערבולת - מעטה של ​​אליהו נופל על אלישע, שגם מחלק את מי הירדן - אלישע מרפא את מי יריחו - בני נוער נקרעים על ידי דובים ללעג אלישע.",
  "2 Kings 3": "יהורם מישראל ויהושפט מיהודה מאחדים כוחות נגד מואב - אלישע מבטיח להם מים לבעלי החיים שלהם וניצחון במלחמה - המואבים מובסים.",
  "2 Kings 4": "אלישע מכפיל את שמן האלמנה - הוא מבטיח בן לאישה שונמית - הילד מת ומוקם לחיים על ידי אלישע - הוא הופך את המזון הרעיל לבלתי מזיק - לחם ותבואה מוכפלים כדי שהעם יאכל.",
  "2 Kings 5": "נעמן, הסורי, מגיע לאלישע כדי להירפא מצרעת - הוא דוחה את הוראת הנביא בתחילה אך מתרצה וטובל בירדן שבע פעמים; הוא נרפא - אלישע מסרב לקבל פרס - גיחזי מקבל מתנה מנעמן ומקולל בצרעת.",
  "2 Kings 6": "אלישע גורם לגרזן לצוף - הוא מגלה למלך איך לנהל מלחמה עם סוריה - סוסים ומרכבות אש מגנים על אלישע - הסורים מוכים בעיוורון - בנהדד מצור על שומרון, ומזון נמכר במחיר מצוין.",
  "2 Kings 7": "אלישע מנבא שפע מדהים בשומרון - הצבאות הסורים בורחים ברעש של קרב ועוזבים את רכושם - ישראל גוזלת שלל מהסורים.",
  "2 Kings 8": "אלישע מנבא רעב של שבע שנים - האישה השונמית נשמרת דרך הרעב - יהורם ואחר כך אחזיהו מלכים ברשע ביהודה.",
  "2 Kings 9": "נביא מושח את יהוא למלך על ישראל ומנבא את חורבן בית אחאב ואת מות איזבל - יהוא הורג את יורם בשדה נבות - איזבל נהרגת על ידי יהוא ונאכלת על ידי כלבים.",
  "2 Kings 10": "שבעים בניו של אחאב נהרגים - יהוא הורס את בית אחאב ואת כל עובדי הבעל, אבל הוא ממשיך לעבוד את עגלי הזהב בבית אל ובדן.",
  "2 Kings 11": "עתליה משמיד את משפחת המלוכה ביהודה וממלכת ביהודה - יואש נשמר ומוכתר למלך בגיל שבע - יהוידע הכהן הורס את בית הבעל.",
  "2 Kings 12": "יהואש (יואש) מושל בצדק - הפרצות בבית המקדש מתוקנות - בטחון ירושלים נקנה עם המקדשים שבבית המקדש - יואש נהרג ואמציהו מלך.",
  "2 Kings 13": "יהואחז וממשיכיו מלכים ברשע בישראל - אלישע מנבא שיואש יביס את סוריה - אלישע מת - בן ישראל מת מוקם לחיים לאחר שנגע בעצמותיו של אלישע.",
  "2 Kings 14": "אמציהו שולט היטב ביהודה - ישראל מנצחת את יהודה בקרב - ירבעם מושל ברשע בישראל.",
  "2 Kings 15": "מלכים רבים מלכים בישראל וביהודה - רשעותם, מלחמותיהם, מזימותיהם ורעותיהם מתוארים - חלק ניכר מישראל נישא בשבי לאשור על ידי תגלת-פילסר.",
  "2 Kings 16": "אחז מושל ברשע ביהודה - הוא מקריב את בנו בהקרבת גויים - הוא עושה מזבח חדש, משחית את ים החצוף ומשנה את שיטת ההקרבה בבית המקדש.",
  "2 Kings 17": "הושע מושל בישראל וכפוף לאשור - בני ישראל עוזבים את ה', עובדים אלילים, עובדים את הבעל ודוחים את כל מה שה' נתן להם - עשרת השבטים נישאים בשבי על ידי מלכי אשור - ארץ ישראל (שומרון) מאוכלסת מחדש על ידי אנשים אחרים - צורות רבות של פולחן שווא נמצאות בקרב השומרונים.",
  "2 Kings 18": "חזקיהו מלך בצדק ביהודה - הוא הורס את עבודת האלילים ושובר את הנחש הנחושת שעשה משה כי בני ישראל מדליקים לו קטורת - סנחריב מלך אשור פולש ליהודה - בנאום חילול הקודש, רבשקה מבקש מירושלים להיכנע לאשור.",
  "2 Kings 19": "חזקיהו מבקש עצה מישעיהו להציל את ירושלים - ישעיהו מנבא את תבוסת האשורים ואת מותו של סנחריב - חזקיהו מתפלל לישועה - סנחריב שולח מכתב חילול הקודש - ישעיהו מנבא שהאשורים ייחרדו וששארית מיהודה תהרוג 500 מלאך - 800 מלאך. אשורים - סנחריב נהרג על ידי בניו.",
  "2 Kings 20": "אומרים לחזקיהו ימות ויתחנן בפני ה'; חייו מתארכים חמש עשרה שנים - הצל חוזר עשר מעלות אחורה על שעון השמש של אחז - ישעיהו מנבא את השבי הבבלי של יהודה.",
  "2 Kings 21": "מנשה הופך את יהודה לעבודת אלילים, אפילו מקריב בן לאל גוי - נביאים חוזים את חורבן יהודה וירושלים - הרשע ממשיך תחת אמון.",
  "2 Kings 22": "יאשיהו מלך בצדק ביהודה - חלקיהו מתקן את בית המקדש ומוצא את ספר התורה - יאשיהו מצטער בגלל רשעות אבותיו - חולדה מנבאת זעם על העם אך ברכה על יאשיהו.",
  "2 Kings 23": "יאשיהו קורא לעם את ספר הברית - כורתים ברית לקיים את המצוות - יאשיהו מבטל את פולחן האלים השקר, מוציא את מעשי הסדום ומפיל את עבודת האלילים - כוהנים עובדי אלילים נהרגים - יהודה מקיים פסח חגיגי - מצרים כפופה את ארץ יהודה.",
  "2 Kings 24": "ירושלים נצורה ונכבשה על ידי נבוכדנצר - רבים מבני יהודה נשבים בשבי לבבל - צדקיהו הופך למלך בירושלים - הוא מורד בבבל.",
  "2 Kings 25": "נבוכדנצר שוב מצור על ירושלים - צדקיהו נכבש, ירושלים ובית המקדש נחרבים, ורוב בני יהודה נישאים לבבל - גדליה, שנותר למשול בשארית, נהרג - השרידים בורחים למצרים - יהויכין זוכה לחסד בבבל.",
  "1 Chronicles 1": "ניתנים אילן היוחסין והקשרים המשפחתיים מאדם לאברהם - צאצאיו של אברהם רשומים.",
  "1 Chronicles 2": "רשומים צאצאיהם של ישראל, יהודה, ישי, כלב ואחרים.",
  "1 Chronicles 3": "בניו של דוד נקראים - יורשיו של שלמה ליקוניה והלאה רשומים.",
  "1 Chronicles 4": "משפחות וצאצאיהם של יהודה, שמעון ואחרים מתועדים - שמות של נסיכים שונים במשפחותיהם.",
  "1 Chronicles 5": "בני יוסף קיבלו את הבכורה של ראובן - יהודה וצאצאיו הפכו לשליטים בישראל - שושלת ראובן עד השבי ניתן - האשורים נושאים את הראובנים, הגדיים וחצי מנשה בשבי.",
  "1 Chronicles 6": "בני לוי, לרבות זמרי דוד, מפורטים - האחריות של אהרון וצאצאיו נתונה - ערי לוים מיועדות בתחומי השבטים השונים.",
  "1 Chronicles 7": "הבנים והמשפחות נקראים על שם יששכר, בנימין, נפתלי, מנשה, אפרים ואשר.",
  "1 Chronicles 8": "שמות בניו וראשי בנימין.",
  "1 Chronicles 9": "תושבי ירושלים רשומים - רשומים האחריות של הלויים והאזורים שבהם הם אמורים לשרת - משפחת שאול נקראת.",
  "1 Chronicles 10": "הפלשתים מנצחים את ישראל - שאול מת על עבירותיו.",
  "1 Chronicles 11": "דוד נמשח למלך בחברון - הוא לוקח את ציון, עיר דוד - קוראים ללוחמיו האמיצים ומספרים על מעשיהם.",
  "1 Chronicles 12": "גבוריו של דוד מקוטלגים - צבאות שבטי ישראל מצטרפים לדוד בחברון - ישראל שמחה בגלל דוד המלך.",
  "1 Chronicles 13": "דוד מביא את הארון מקרית-יערים - עוזה נהרג על ידי ה' כשהוא מייצב את הארון - בית עובד אדום משגשג כי הם דואגים לתיבה.",
  "1 Chronicles 14": "דוד מתחתן עם נשים, מוליד ילדים ומביס את הפלשתים; תהילתו מתפשטת לכל העמים.",
  "1 Chronicles 15": "דוד מכין מקום לארון-הלויים מביאים את הארון לירושלים-הם שרים ומשרתים לפני ה'.",
  "1 Chronicles 16": "אנשים מקריבים קורבנות ומשבחים את ה' - דוד מביא מזמור הודיה - הוא משבח את ה' - אסף, עובד אדום, צדוק ואחרים שרים לפני ה'.",
  "1 Chronicles 17": "נתן מאשר תחילה את בניית בית ה' על ידי דוד, אחר כך מעכב אותו - בנו של דוד יבנה את בית המקדש - נצחון ישראל ידוע מראש - דוד מודה לה' על טובתו לישראל.",
  "1 Chronicles 18": "דוד מכניע את כל אויבי ישראל וממלוך צדק על העם.",
  "1 Chronicles 19": "העמונים מעליבים את שליחי דוד ומתכננים מלחמה נגד ישראל - דוד מביס את העמונים ואת הסורים.",
  "1 Chronicles 20": "העמונים מתגברים - ישראל מנצחת את הפלשתים.",
  "1 Chronicles 21": "דוד חוטא במספור ישראל - ה' שולח מגיפה על העם - דוד מקריב קורבנות והמגפה נעצרת.",
  "1 Chronicles 22": "דוד מכין זהב, כסף, פליז, ברזל, אבן ועצי ארז לבית המקדש - הוא מצווה על שלמה לעשות את מלאכת בנייתו.",
  "1 Chronicles 23": "שלמה ממונה למלך - הלויים ממוספרים ומוטטים את חובותיהם הדתיות השונות.",
  "1 Chronicles 24": "בני אהרן ושאר בני לוי מחולקים לקבוצות ומחלקים את תפקידיהם בהגרלה.",
  "1 Chronicles 25": "על הזמרים והנגנים הלויים מוטל תפקידיהם בהגרלה.",
  "1 Chronicles 26": "הלויים מוקצים כסבלים - הם ממונים על האוצרות, משמשים קצינים ושופטים ומנהלים את העסקים החיצוניים הנוגעים לבני ישראל.",
  "1 Chronicles 27": "הקצינים המשרתים את המלך נקראים - הנסיכים של שבטי ישראל מוצגים.",
  "1 Chronicles 28": "דוד אוסף את מנהיגי ישראל - שלמה מתמנה לבנות את בית המקדש - דוד קורא לשלמה ולעם לקיים את המצוות - דוד נותן לשלמה את התבנית והחומרים לבית המקדש.",
  "1 Chronicles 29": "כל ישראל מקריבים קורבן ליברלי לבית המקדש - דוד מברך ומשבח את ה' ומנחה את העם - דוד מת - שלמה מלך כמלך - מוזכרים ספרי נתן וגד.",
  "2 Chronicles 1": "ה' מכבד את שלמה לפני כל ישראל - ה' נגלה אליו - שלמה בוחר וניתנת לו חכמה - מלכותו מתברכת בהדר ובעושר.",
  "2 Chronicles 2": "שלמה מעסיק את חורם מצור לספק עצים לבית המקדש - פועלים מאורגנים לעשות את העבודה.",
  "2 Chronicles 3": "שלמה מתחיל לבנות את בית המקדש - הוא עושה את הפרוכת ואת העמודים, ומשתמש הרבה בזהב ובהרבה אבנים יקרות.",
  "2 Chronicles 4": "שלמה מכין אגן ומניח אותו על שנים עשר שוורים - המזבח, האגנים, הסירים ופריטים שונים עשויים.",
  "2 Chronicles 5": "גמר המקדש, וארון הברית מוצב בקודש הקדשים - כבוד ה' ממלא את המקדש.",
  "2 Chronicles 6": "שלמה מברך את עדת ישראל - הוא נושא את תפילת הקדשה לבית המקדש - הוא מתפלל רחמים וברכות לישראל חוזרים בתשובה.",
  "2 Chronicles 7": "אש יורדת מהשמים ומכלה את הקורבנות והעולה - ה' נגלה לשלמה ומבטיח לברך את העם - בני ישראל יצליחו אם ישמרו את המצוות.",
  "2 Chronicles 8": "שלמה בונה ערים - הוא מקריב קורבנות על פי תורת משה - מתמנים כוהנים ולווים לעבוד את ה'.",
  "2 Chronicles 9": "מלכת שבא מבקרת את שלמה - הוא מצטיין בחוכמה, עושר והדר - לאחר מלכות ארבעים שנה, שלמה מת, ורחבעם הופך למלך.",
  "2 Chronicles 10": "העם מבקש הקלה, אך רחבעם מבטיח להגביר את הנטל על העם - ישראל מורדים והממלכה מפולגת.",
  "2 Chronicles 11": "רחבעם מחזק את ממלכת יהודה אך נאסר עליו להכניע את ישראל - ירבעם מוביל את ממלכת ישראל לעבודת אלילים - רחבעם לוקח הרבה נשים ופיגשים.",
  "2 Chronicles 12": "רחבעם עוזב את תורת ה' - המצרים שודדים את ירושלים ולוקחים את אוצרות בית ה' - העם חוזר בתשובה ומקבל הצלה חלקית - רחבעם מת.",
  "2 Chronicles 13": "אביה מלך ביהודה - הוא מביס את ירבעם ואת צבאות ישראל - ה' מכה את ירבעם, והוא מת.",
  "2 Chronicles 14": "אסא מלך ביהודה, בונה מחדש את הערים, מביס ובוזז את האתיופים, שתוקפים את יהודה.",
  "2 Chronicles 15": "עזריה מנבא שיהודה תשגשג אם העם יקיים את המצוות - אסא מבטל את עבודת השווא ביהודה - רבים מאפרים, מנשה ושמעון נודדים ליהודה - העם כורת ברית לעבוד את ה' ויתברך.",
  "2 Chronicles 16": "אסא מעסיק את סוריה כדי להביס את ישראל - חנני הרואה מוכיח את אסא מחוסר אמונה - אסא סובל ממחלות ומת.",
  "2 Chronicles 17": "יהושפט מושל היטב ומשגשג ביהודה - כוהנים נוסעים ומלמדים מתוך ספר תורת ה'.",
  "2 Chronicles 18": "יהושפט מיהודה מצטרף לאחאב מישראל כדי להילחם בסוריה - נביאי השקר של אחאב מנבאים ניצחון - מיכיה מנבא את נפילתו ומותו של אחאב - הסורים הורגים את אחאב.",
  "2 Chronicles 19": "יהושפט ננזף על כך שעזר לאחאב הלא אלוהים - הוא עוזר לעם לשוב אל ה', מקים שופטים ועושה משפט.",
  "2 Chronicles 20": "בני עמון ואחרים תוקפים את יהודה - יהושפט וכל העם צמים ומתפללים - יחזיאל מנבא את הצלת יהודה - תוקפי יהודה לוחמים ביניהם ומשמידים את עצמם.",
  "2 Chronicles 21": "יהורם הורג את אחיו, מתחתן עם בתו של אחאב וממלוך ברשע - אליהו מנבא מגפה על העם ומותו של יהורם - הפלשתים ואחרים לוחמים ביהודה - יהורם מת ממחלות קשות.",
  "2 Chronicles 22": "אחזיהו מלך ברשע ונהרג על ידי יהוא; אמו, עתליה, ממלכת במקומו.",
  "2 Chronicles 23": "יהוידע הכהן ממליך את יואש - עתליה נהרג - עבודת ה' חוזרת, וכהן הבעל נהרג.",
  "2 Chronicles 24": "יואש ויהוידע מקבלים תרומות ומתקנים את בית ה' - יהוידע מת - יואש נופל לעבודת אלילים, הורג נביא בשם זכריה, ובעצמו נהרג בקונספירציה.",
  "2 Chronicles 25": "אמציהו מלך, מכה את האדומים וסוגד לאלי שקר - נביא מנבא את חורבן אמציהו - יהודה מובס על ידי ישראל, ואמציה נהרג בקונספירציה.",
  "2 Chronicles 26": "עוזיהו ממלוך ומשגשג כל עוד הוא מקיים את המצוות - הוא עובר על, מנסה להקטיר קטורת על המזבח ומקולל בצרעת.",
  "2 Chronicles 27": "יותם ממלוך, בונה את הממלכה ומכניע את בני עמון.",
  "2 Chronicles 28": "אחז מושל ברשע ועושה עבודת אלילים; עמו מובס על ידי ישראל - השבויים משוחררים בפקודת נביא - האדומים והפלשתים תוקפים את יהודה - אחז ממשיך בדרכי האלילים שלו.",
  "2 Chronicles 29": "חזקיהו מלך בצדק ומחזיר את עבודת יהוה - הלויים מטהרים ומקדשים את בית ה' - הכוהנים מקריבים קורבנות ועושים פיוס ומכפרים על העם - חזקיהו וכל העם עובדים את ה' ומשבחים את שמו.",
  "2 Chronicles 30": "חזקיהו מזמין את כל ישראל לפסח חגיגי בירושלים — יש המקשיבים לקריאה; אחרים צוחקים אותו בבוז - בני ישראל הנאמנים עובדים את ה' בירושלים.",
  "2 Chronicles 31": "בני ישראל הנאמנים מפילים בקרבם את פולחן השקר - העם משלם מעשר ומנחות - הלויים מנהלים בענייני זמן - חזקיהו משרת נאמנה.",
  "2 Chronicles 32": "סנחריב פולש ליהודה ומצור על הערים - הוא מתרעם על ה' - ישעיהו וחזקיהו מתפללים, ומלאך משמיד את מנהיגי צבאות אשור - חזקיהו מושל בצדק למרות גאווה מסוימת בלבו.",
  "2 Chronicles 33": "מנשה מושל ברשע וסוגד לאלי שקר - הוא נלקח בשבי לאשור - הוא חוזר בתשובה ומשרת את ה' - אמון מושל בעוולה ונהרג.",
  "2 Chronicles 34": "יאשיהו משמיד את עבודת האלילים ביהודה - בני יהודה מתקנים את בית ה' - חלקיהו מוצא ספר חוק - חולדה הנביאה מגלה את השממות שיבואו על העם - יאשיהו והעם כורתים ברית לעבוד את ה'.",
  "2 Chronicles 35": "יאשיהו וכל יהודה מקיימים פסח חגיגי ביותר - יאשיהו נפצע אנושות על ידי המצרים במגידו.",
  "2 Chronicles 36": "מלכים שונים שולטים ביהודה - נבוכדנצר מכניע את יהודה וממליך את צדקיהו - צדקיהו מורד, העם דוחה את הנביאים והכשדים שורפים את בית המקדש ומחריבים את ירושלים - כורש הפרסי גוזר על בניית המקדש.",
  "Ezra 1": "מלך פרס כורש נותן ליהודים לחזור לירושלים לבנות את בית המקדש - כורש מחזיר את כלי בית ה' שנלקחו על ידי נבוכדנצר.",
  "Ezra 2": "רשומים צאצאיהם של היהודים שנפלו בשבי החוזרים לירושלים וליהודה - ילדי הכוהנים שמשפחתם אבודה נשללת הכהונה - אנשים נאמנים תורמים לבניין המקדש.",
  "Ezra 3": "המזבח נבנה מחדש - מחזירים קורבנות רגילים - יסודות המקדש מונחים תוך שמחה גדולה.",
  "Ezra 4": "השומרונים מציעים עזרה, ואז מעכבים את העבודה - בניית המקדש וחומות ירושלים נפסקת.",
  "Ezra 5": "חגי וזכריה מתנבאים - זרובבל מחדשת את בניין המקדש - השומרונים קוראים תיגר על זכותם של היהודים להמשיך בעבודות הבנייה שלהם.",
  "Ezra 6": "דריוש מחדש את גזרת כורש לבנות את בית המקדש - הוא הסתיים ונחנך, ושוב מתחילים קורבנות ומשתה.",
  "Ezra 7": "עזרא עולה לירושלים - ארתחשסתא דואג ליפיוף בית המקדש ומקיים את היהודים בפולחנם.",
  "Ezra 8": "העולים מבבל לירושלים רשומים - הלויים נקראים ללוות אותם - עזרא והעם צמים ומתפללים ומקבלים הדרכה והגנה ביציאה לירושלים.",
  "Ezra 9": "יהודים רבים מתחתנים עם הכנענים ואחרים ועוקבים אחר תועבותיהם - עזרא מתפלל ומתוודה על חטאי כל העם.",
  "Ezra 10": "היהודים כורתים את נשותיהם שנלקחו מהכנענים ואחרים - עזרא אוסף את העם בירושלים - רשומים הלויים שנישאו לנשים שאינן ישראליות.",
  "Nehemiah 1": "נחמיה אבל, צום ומתפלל למען היהודים בירושלים.",
  "Nehemiah 2": "ארתחשסתא שולח את נחמיה לירושלים - סנבלט ואחרים מתנגדים לנחמיה בבנייה מחדש של חומות ושערי ירושלים.",
  "Nehemiah 3": "מופיעים שמות וסדר המסייעים בבניית חומות ושערי ירושלים.",
  "Nehemiah 4": "אויביהם של היהודים מבקשים למנוע מהם לבנות מחדש את חומות ירושלים - נחמיה מחמש את הפועלים ושומר על התקדמות העבודה.",
  "Nehemiah 5": "יהודים רבים נמצאים בשיעבוד לאחיהם היהודים - בהוראת נחמיה הם משוחררים, אדמותיהם משוחזרות, ונטילת הריבית מופסקת.",
  "Nehemiah 6": "סנבלט עוסק בתככים נגד נחמיה ובניית החומה - היהודים מסיימים את בניית החומה.",
  "Nehemiah 7": "נקבעו הוראות להגנה על ירושלים - שושלת היוחסין מובאת של היהודים שחזרו מבבל - כוהנים ללא תיעוד יוחסין נשללים מהכהונה.",
  "Nehemiah 8": "עזרא קורא ומפרש את תורת משה לעם - הם מקיימים את חג הסוכות.",
  "Nehemiah 9": "היהודים צמים ומתוודים על חטאיהם - הלויים מברכים ומשבחים את ה' וקוראים את טובתו לישראל.",
  "Nehemiah 10": "העם כורת ברית לא להתחתן מחוץ לישראל - הם גם כורתים ברית לכבד את השבת, לשלם מעשר ולקיים מצוות.",
  "Nehemiah 11": "העם ומשגיחיו נבחרים בהגרלה לשכון בירושלים ובשאר הערים.",
  "Nehemiah 12": "הכוהנים והלויים שעלו מבבל נקראים - חומות ירושלים מוקדשות - משרות הכהנים והלויים ממונים בבית המקדש.",
  "Nehemiah 13": "מהעמונים והמואבים נמנעים ממקום בקהילת ה' - טוביה נפלט ממקום מגוריו בבית המקדש - נחמיה מתקן התעללויות ומחזיר את שמירת השבת - יש יהודים שננזפים על שהתחתנו עם נשים שאינן ישראליות ומטמאים את הכהונה.",
  "Esther 1": "אחשוורוש מפרס ומדי עורך סעודות מלכותיות - ושתי אינו מציית למלך ומודח כמלכה.",
  "Esther 2": "אחשוורוש מחפש מלכה חדשה - מרדכי מציג את אסתר - אסתר מוצאת חן בעיני המלך ונבחרת למלכה - מרדכי חושף מזימה נגד המלך.",
  "Esther 3": "מרדכי, היהודי, מסרב להשתחוות להמן - המן מסדר גזירה להרוג את כל היהודים בממלכה.",
  "Esther 4": "מרדכי והיהודים אבלים וצמים על צו המלך - אסתר, בסכנת חייה, מתכוננת להיכנס אל המלך.",
  "Esther 5": "המלך מקבל את אסתר - היא מזמינה אותו ואת המן למשתה - המן מתכנן לתלות את מרדכי.",
  "Esther 6": "מרדכי זוכה לכבוד גדול - המן מתאבל ומייעץ מאשתו.",
  "Esther 7": "אסתר חושפת את מזימתו של המן להשמיד את היהודים - הוא נתלה על גרדום עצמו.",
  "Esther 8": "מרדכי זוכה לכבוד ומוצב על בית המן - אחשורוש מוציא גזירה לשמור על היהודים.",
  "Esther 9": "היהודים הורגים את אויביהם, כולל עשרת בניו של המן - חג הפורים נוסד כדי להנציח את גאולתם וניצחונם.",
  "Esther 10": "מרדכי, היהודי, עומד לצד אחשוורוש בכוח ובעוצמה.",
  "Job 1": "איוב, איש צודק ומושלם, התברך בעושר רב - השטן מקבל רשות מה' לפתות ולנסות את איוב - רכושו וילדיו של איוב נהרסו, ובכל זאת הוא מהלל ומברך את ה'.",
  "Job 2": "השטן מקבל רשות מהאדון להציק לאיוב פיזית - איוב מוכה שחין - אליפס, בילדד וצופר באים לנחם אותו.",
  "Job 3": "איוב מקלל את נסיבות לידתו - הוא שואל, מדוע לא מתתי מהרחם?",
  "Job 4": "אליפז מוכיח את איוב, ושואל שאלות כמו, האם הצדיקים נכרתים? האם יהיה אדם טהור יותר מיוצרו?",
  "Job 5": "אליפז מייעץ לאיוב: האדם נולד לצרה, חפש את אלוהים, ושמח האדם שאלוהים מתקן.",
  "Job 6": "איוב מבכה את צערו - הוא מתפלל שאלוהים ייעתר לבקשותיו - יש לרחם על הסובלים - כמה כוחניות הן המילים הנכונות!",
  "Job 7": "איוב שואל, האם יש זמן קבוע לאדם עלי אדמות? מהו האדם שתגדל אותו? מדוע אינך סולחת על עבירתי?",
  "Job 8": "בילדד שואל, האם אלוהים מעוות את הדין? - בילדד אומר, ימינו עלי אדמות הם צל, ואלוהים לא ישליך אדם מושלם.",
  "Job 9": "איוב מכיר בצדקתו ובגדולתו של אלוהים ומגיע למסקנה שהאדם אינו יכול להתמודד נגדו.",
  "Job 10": "איוב עייף מהחיים - הוא מתלבט עם אלוהים על ייסוריו - הוא שואל, למה הוצאת אותי מהרחם?",
  "Job 11": "זופר שואל, האם אתה יכול בחיפוש לגלות את אלוהים? - צופר אומר שתקוות הרשעים תתפוגג כאילו היא מתה.",
  "Job 12": "איוב אומר, נשמות הכל בידי ה', עם הקדמונים היא חכמה, וה' מושל בכל דבר.",
  "Job 13": "איוב מעיד על בטחונו בה' ואומר, אף על פי שהרג אותי, אך אבטח בו, והוא גם יהיה לי לישועה.",
  "Job 14": "איוב מעיד על קוצר החיים, על וודאות המוות והערבות לתחיית המתים - הוא שואל, אם אדם ימות, האם הוא יחיה שוב? - איוב עונה שהוא ימתין לקריאת ה' לצאת מהקבר.",
  "Job 15": "אליפז מציג את חוסר השקט של אנשים רשעים - הם לא מאמינים שהם ישובו מהחושך ויקומו לתחייה.",
  "Job 16": "איוב מדבר נגד הרשעים שמתנגדים לו - אף על פי שאפילו חבריו מזלזלים בו, הוא מעיד שהעד שלו בשמים ורישומו גבוה.",
  "Job 17": "איוב מדבר על צער המוות ועל הקבר ביום ההוא שבו הגוף חוזר לעפר.",
  "Job 18": "בילדד מספר על מצבם הארור של הרשעים שאינם מכירים את אלוהים.",
  "Job 19": "איוב מספר על התחלואים שפקדו אותו ואז מעיד, אני יודע שהגואל שלי חי - איוב מנבא שהוא יקום לתחייה ושעל בשרו הוא יראה את אלוהים.",
  "Job 20": "צופר מראה את מצבו של הרשע - הוא אומר, נצחון הרשע קצר, ושמחת הצבוע היא רק לרגע.",
  "Job 21": "איוב מודה שהרשעים לפעמים משגשגים בחיים האלה - ואז הוא מעיד שדינם יהיה להלן ביום הכעס והחורבן.",
  "Job 22": "אליפז מאשים את איוב בחטאים שונים וקורא לו לחזור בתשובה.",
  "Job 23": "איוב מחפש את ה' ומצהיר על צדקתו - הוא אומר, כאשר ה' ניסה אותי, אני אצא כמו זהב.",
  "Job 24": "רוצחים, נואפים, אלה שמדכאים את העניים, ואנשים רשעים בכלל לא נענשים לזמן מה.",
  "Job 25": "בילדד מבכה את מצבו השפל של האדם ומסווג אותו כתולעת.",
  "Job 26": "איוב מוכיח את חוסר האמפתיה של בילדד - הוא משבח את כוחו, גדולתו ועוצמתו של האדון.",
  "Job 27": "איוב תוקף את צדקתו - כאשר רשעים יקברו במוות, אימה תאחז בהם.",
  "Job 28": "עושר יוצא מן הארץ - אין אפשרות לקנות חכמה - יראת ה' היא חכמה, ולסור מרע זה בינה.",
  "Job 29": "איוב נזכר בשגשוגו ובגדולתו הקודמים - הוא התברך בגלל צדקתו, צדקתו ומעשיו הטובים.",
  "Job 30": "איוב זוכה ללעג על ידי ילדיהם של אנשים שפלים ושפלים - במצבו הפגוע, הוא בוכה אל ה' - איוב אומר שהוא בכה על מי שנמצא בצרות.",
  "Job 31": "איוב מזמין משפט כדי שאלוהים יידע את יושרו - אם עשה רע, איוב מברך על העונשים על כך.",
  "Job 32": "אליהו, בכעס, עונה לאיוב ושלושת חבריו - אליהו אומר, יש רוח באדם, והשראת הקב\"ה נותנת בינה - הוא גם אומר, אנשים גדולים לא תמיד חכמים.",
  "Job 33": "אליהו אומר, אלוהים גדול מהאדם, הוא מדבר אל האדם בחלומות ובחזיונות, הוא פודה את המושלכים לבור, ומציל את נפשם ומעניק להם חיים.",
  "Job 34": "אליהו מלמד, אלוהים אינו יכול להיות עוול, לעשות עוון, להעוות משפט או לכבד אנשים - האדם צריך לשאת ייסורים ולא לעשות עוון יותר.",
  "Job 35": "אליהו עומד בניגוד לחולשת האדם ולכוחו של אלוהים - רשעותנו פוגעת באנשים אחרים, וצדקתנו עוזרת להם - האדם צריך לבטוח בה'.",
  "Job 36": "אליהו אומר, הצדיקים משגשגים - רשעים מתים ומתים ללא ידיעה - אליהו משבח את גדלות ה'.",
  "Job 37": "אליהו מסכם ואומר, ה' שולט בחוקי הטבע - אלוהים מושל בהוד נורא.",
  "Job 38": "אלוהים שואל את איוב היכן היה כאשר הונחו יסודות הארץ, כאשר שרו כוכבי הבוקר יחדיו, וכאשר כל בני האלוהים צעקו משמחה - תופעות הטבע מראות את גדולתו של אלוהים ואת חולשת האדם.",
  "Job 39": "חולשת האדם ובורותו מושווים למעשיו האדירים של אלוהים - האם האדם בכלל יודע כיצד פועלים חוקי הטבע?",
  "Job 40": "ה' קורא תיגר על איוב, ואיוב משיב בענווה - ה' מדבר על כוחו לאיוב - הוא שואל, האם יש לך זרוע כמו אלוהים? - הוא מצביע על כוחו בהמה.",
  "Job 41": "ה' מצביע על כוחו בלווייתן - כל הדברים מתחת לכל השמים הם של ה'.",
  "Job 42": "איוב חוזר בתשובה בעפר ובאפר - הוא רואה את ה' בעיניו - ה' מייסר את חבריו של איוב, מקבל את איוב, מברך אותו והופך את אחרית ימיו לגדולים מראשיתו.",
  "Psalms 1": "אשרי הצדיקים-הרשעים יאבדו.",
  "Psalms 2": "מזמור משיחי - הגויים ישתוללו על המשוחים של ה' - ה' מדבר על בנו, אותו הוליד.",
  "Psalms 3": "דוד זועק אל ה' ונשמע - הישועה היא מה'.",
  "Psalms 4": "דוד מתחנן לרחמים - הוא מייעץ, בטחך בה'.",
  "Psalms 5": "דוד מבקש מה' לשמוע בקולו - ה' שונא פועלי עוון - הוא מברך ומגן על צדיקים.",
  "Psalms 6": "דוד זועק אל ה' לרחמים - הוא מבקש להירפא ולהינצל.",
  "Psalms 7": "דוד בוטח בה', שישפוט את העם - אלוהים כועס על הרשעים.",
  "Psalms 8": "מזמור משיחי לדוד - הוא אומר כי תינוקות וילדים משבחים את ה' - הוא שואל, מה זה אדם, כי אתה מודע אליו?",
  "Psalms 9": "מזמור משיחי לדוד - הוא משבח את ה' על גער בגויים - ה' ישפוט את העולם בצדק - ישכון בציון - הרשעים ישלחו לגיהנום.",
  "Psalms 10": "דוד מדבר על מעשים שונים של רשעים - אלוהים אינו במחשבותיהם - אבל ה' מלך לעולם ועד - ישפוט יתום ונדכא.",
  "Psalms 11": "דוד שמח על כך שה' נמצא בהיכל קדשו - ה' בוחן את הצדיקים ושונא את הרשעים.",
  "Psalms 12": "דוד מגנה שפתיים מחמיאות ולשונות גאות - הוא אומר, דברי ה' הם דברים טהורים.",
  "Psalms 13": "דוד בוטח ברחמי ה' ושמח בישועתו.",
  "Psalms 14": "דוד אומר, שוטה אמר בלבו, אין אלוהים - ישמח ישראל ביום התקומה.",
  "Psalms 15": "דוד שואל, מי ישכון בגבעת קודש ה'? - הוא עונה, צדיקים, ישרים ובעלי יושרה.",
  "Psalms 16": "מזמור משיחי לדוד - הוא שמח בקדושים אשר על פני האדמה, בגאולה העתידית שלו מהגיהנום, בעובדה שאלוהים לא יסבול מקדושתו (המשיח) לראות שחיתות, ובמלוא השמחה שנמצאת בנוכחות ה'.",
  "Psalms 17": "דוד מתחנן בפני ה' לשמוע בקולו ולשמור עליו מאנשי העולם - דוד מקווה לראות את פני ה' בצדק.",
  "Psalms 18": "דוד משבח את ה' על גדלותו ודאגתו המשמרת - דרכו של ה' מושלמת - ה' נתן ברכות נפלאות - דוד מעיד, ה' חי וברוך הסלע שלי.",
  "Psalms 19": "דוד מעיד, השמים מכריזים על כבוד ה', תורת ה' היא מושלמת, ומשפטי ה' אמת וצדקה לגמרי.",
  "Psalms 20": "דוד מתפלל שה' ישמע בשעת צרה - ה' מציל את המשוח שלו.",
  "Psalms 21": "מזמור משיחי לדוד - הוא מספר על תהילתו של המלך הגדול - המלך ינצח על כל אויביו - תכניותיהם הרעות ייכשלו.",
  "Psalms 22": "מזמור משיחי לדוד - הוא מנבא אירועים בחייו של המשיח - המשיח יאמר: אלוהי אלוהיי למה עזבת אותי? - הם יחקרו את ידיו ורגליו - הוא עוד ישלוט בכל העמים.",
  "Psalms 23": "דוד מכריז, ה' הוא הרועה שלי.",
  "Psalms 24": "דוד מעיד, הארץ היא של ה' ומלואו, מי שיש לו ידיים נקיות ולב טהור יעלה אל גבעת ה', וה' צבאות הוא מלך הכבוד.",
  "Psalms 25": "דוד מתחנן לאמת ומבקש סליחה - רחמים ואמת הם לשומרי המצוות.",
  "Psalms 26": "דוד אומר שהוא התהלך ביושרה ובציות - הוא אוהב את בית ה'.",
  "Psalms 27": "דוד אומר, ה' הוא האור שלי וישועתי - הוא חפץ לשבת בבית ה' לנצח - הוא מייעץ, חכה לה' ותהיה אומץ.",
  "Psalms 28": "דוד מתחנן בפני ה' שישמע בקולו וייעתר לבקשותיו - דוד מתפלל, הושיע את עמך וברך את נחלתך.",
  "Psalms 29": "דוד מייעץ, עבדו את ה' ביופי של קדושה - דוד מציג את הפלא ועוצמתו של קול ה'.",
  "Psalms 30": "דוד שר הלל ומודה לה' - דוד מתחנן לרחמים.",
  "Psalms 31": "דוד בוטח בה' ושמח ברחמיו - מדבר כמשיח הוא אומר, בידך אני נותן רוחי - הוא מייעץ, אהב את ה', כל קדושיו, כי ה' שומר על הנאמנים.",
  "Psalms 32": "דוד אומר, אשרי האיש אשר ה' לא ייחס לו עוון - דוד מודה בחטאו - הוא ממליץ לצדיקים שישמחו בה' וישמחו.",
  "Psalms 33": "שמח בה'-שירו לו שירה חדשה-אוהב צדקה ומשפט-אשרי העם אשר ה' אלוהיו.",
  "Psalms 34": "דוד מברך את ה' בכל עת--יעץ, שמר לשונך מרע; עשה טוב וחפש שלום - הוא אומר שאף אחת מעצמות המשיח לא תישבר.",
  "Psalms 35": "דוד מתלונן על אויביו ועל מעשיהם השגויים - הוא מבקש מה' לשפוט אותו לפי צדקתו.",
  "Psalms 36": "דוד משבח את ה' על חסדו, צדקתו וחסדיו - מעיין החיים עם ה'.",
  "Psalms 37": "דוד מייעץ, בטח בה' ועשה טוב - נח בה' וחכה לו בסבלנות - חדל מכעס ותעזוב את הכעס - הענווים יירשו את הארץ - ה' אוהב צדק ואינו נוטש את קדושיו.",
  "Psalms 38": "דוד מצטער על חטאיו - הם נחים עליו כמחלה - הוא מבקש מהאלוהים לרחם.",
  "Psalms 39": "דוד מבקש לשלוט בלשונו - האדם הוא לגמרי הבל - הוא זר וגרה על פני האדמה.",
  "Psalms 40": "מזמור משיחי לדוד - יבוא המשיח ויבשר צדקה - יגיד ישועה - יגידו הצדיקים גדל ה'.",
  "Psalms 41": "מזמור משיחי לדוד - אשרי המתחשב בעניים - בוגדתו של יהודה ידועה מראש.",
  "Psalms 42": "נפשם של צדיקים צמאות לה' - הרשעים אומרים היכן אלוהיך?",
  "Psalms 43": "הצדיקים משבחים את ה' וזועקים, שלח את אורך ואת האמת שלך.",
  "Psalms 44": "הקדושים משבחים את האדון ומתפארים בשמו לנצח - הם נרדפים, מושמצים ונחשבים כצאן לטבח.",
  "Psalms 45": "מזמור משיחי - המשיח יפה יותר מבני האדם - הוא נמשח בשמן שמחה מעל רעיו - שמו ייזכר בכל הדורות.",
  "Psalms 46": "אלוהים הוא מקלטנו וחוזקנו - הוא שוכן בעירו, עושה נפלאות, ואומר, שקט ודעו כי אני אלוהים.",
  "Psalms 47": "ה' הוא מלך על כל הארץ - שירו ​​הלל לשמו, כי הוא מלך על הכל.",
  "Psalms 48": "ציון, עיר האלוהים, שמחת כל הארץ, תקום לעד.",
  "Psalms 49": "לא ניתן לפדות בני אדם או לגאול על ידי עושר - אלוהים לבדו יכול לגאול נשמה מהקבר - תהילתו של עשיר נפסקת עם מותו.",
  "Psalms 50": "אסף מדבר על הביאה השנייה - ה' מקבל את קורבנות הצדיקים ויציל אותם - מי שהתנהגותו נכונה יראה את ישועת ה'.",
  "Psalms 51": "דוד מתחנן לסליחה לאחר שנכנס לבת שבע - הוא מתחנן, צור בי לב נקי, ותחדש רוח נכונה בתוכי.",
  "Psalms 52": "דוד אומר שלשונות רשעות ממצות רעות והרשעים סומכים על עושר - הקדושים בוטחים בחסדי אלוהים לנצח.",
  "Psalms 53": "דוד אומר, השוטה אומר אין אלוהים - אין עושה טוב - ישמחו אספו ישראל.",
  "Psalms 54": "דוד מתחנן לישועה ומבטיח לעבוד את אלוהים.",
  "Psalms 55": "דוד מתפלל בוקר, צהריים ולילה - הוא מחפש הגנה ועזרה מפני אויביו.",
  "Psalms 56": "דוד מבקש רחמים, סומך על ה' ומשבח אותו, ומודה לו על הגאולה.",
  "Psalms 57": "דוד מתחנן לרחמים ומשבח את כבודו ורוממותו של אלוהים.",
  "Psalms 58": "דוד מוכיח שופטים רשעים - הם הולכים שולל ומדברים שקרים.",
  "Psalms 59": "דוד מתפלל להינצל מאויביו - אלוהים שולט ביעקב עד קצה הארץ.",
  "Psalms 60": "דוד אומר שה' פיזר את עמו - ה' שם את אפרים בראש והופך את יהודה לחוקק שלו.",
  "Psalms 61": "דוד מוצא מחסה באלוהים, שוכן בנוכחות ה' ומקיים את נדריו שלו.",
  "Psalms 62": "דוד משבח את אלוהים כהגנה שלו, סלע וישועתו - ה' שופט את בני האדם על פי מעשיהם.",
  "Psalms 63": "דוד צמא לאלוהים, אותו הוא משבח בשפתיים משמחות.",
  "Psalms 64": "דוד מתפלל לבטחון - הצדיקים ישמחו בלב.",
  "Psalms 65": "דוד מדבר על ברכת נבחרי אלוהים - ה' מוריד גשם ודברים טובים על הארץ.",
  "Psalms 66": "הלל ועבוד את ה' - הוא מנסה ומנסה אנשים - יש להקריב קורבנות בביתו.",
  "Psalms 67": "מזמור משיחי - ה' ישאיר פניו על בני האדם - ישפוט וישלוט בצדק.",
  "Psalms 68": "מזמור משיחי לדוד - הוא משבח את י' - ה' נתן את המילה - הוא לוקח בשבי - הוא מציל אותנו ממוות - שירו ​​הלל לה'.",
  "Psalms 69": "מזמור משיחי לדוד - קנאות בית ה' אכלה אותו - חרפה שברה את לבו - נותנים לו מרה וחומץ לשתות - הוא נרדף - הוא יציל את ציון.",
  "Psalms 70": "דוד מכריז, יתגדל אלוהים.",
  "Psalms 71": "דוד משבח את אלוהים בהודיה - מי דומה ליהוה!",
  "Psalms 72": "דוד מדבר על שלמה, שנעשה לטיפוס של המשיח - יהיה לו שלטון - שמו יעמוד לעד - כל העמים יקראו אותו מבורך - כל הארץ תתמלא בכבוד ה'.",
  "Psalms 73": "אלוהים טוב לישראל - הרשעים והרשעים משגשגים בעולם הזה - הם יאכלו אימים מכאן ומכאן - הבוטחים בה' יתקבלו לתפארת.",
  "Psalms 74": "אלוהים, זכור את עדתך הנבחר - הרשעים הורסים את המקדש ושורפים את בתי הכנסת - אלוהים, זכור אותם על מעשיהם, והושיע את עמך.",
  "Psalms 75": "הצדיקים משבחים ומודים לאלוהי יעקב - יתנשאו - ה' הוא השופט, והרשעים יורשעו.",
  "Psalms 76": "אלוהים ידוע ביהודה ושוכן בציון - הוא יציל את עניו הארץ.",
  "Psalms 77": "צדיקים זועקים לה' - זוכרים נפלאות של פעם איך גאל את בני יעקב והוביל את ישראל כצאן.",
  "Psalms 78": "בני ישראל צריכים ללמד את תורת יהוה לילדיהם - ישראל הסוררים התגרה באלוהים במדבר - מכותרות מכות מצרים - ה' בוחר ומברך את יהודה ודוד.",
  "Psalms 79": "העמים הגויים הורסים את ירושלים ומטמאים את בית המקדש - ישראל מתחננת לסליחה ולגאולה.",
  "Psalms 80": "ישראל מתחנן בפני רועה ישראל לישועה, לישועה ולפניו שיאירו עליהם.",
  "Psalms 81": "ישראל מצווה לשיר הלל לאלוהים - אילו היו בני ישראל הולכים בדרכי ה', הם היו מנצחים את אויביהם.",
  "Psalms 82": "כֹּה אָמַר יְהוָה, אֱלֹהִים וּבְנֵי אֱלֹהִים אַתֶּם.",
  "Psalms 83": "אלוהים מתבקש לבלבל את אויבי עמו - יהוה הוא העליון על כל הארץ.",
  "Psalms 84": "צדיקים זועקים לאלוקים חיים - מוטב להיות שוער בבית ה' מאשר לשכון באוהלי רשעים - שום דבר טוב לא נמנע מההולכים ביושר.",
  "Psalms 85": "יהוה מדבר שלום לעמו - האמת תצוץ מתוך הארץ (ספר המורמון), וצדקה תביט משמים.",
  "Psalms 86": "דוד מפציר באלוהים לרחמים וניצל מהגיהנום הנמוך ביותר - ה' טוב ונדיב ברחמים - כל העמים יעבדו לפניו.",
  "Psalms 87": "ה' אוהב את שערי ציון, והוא בעצמו יקים את ציון.",
  "Psalms 88": "תפילה של מי שמרגיש נטוש ושואל אם חסד ה' יוכרז בקבר.",
  "Psalms 89": "מזמור משיחי-שיר המציג את רחמיו, גדלות, צדק וצדקתו של קדוש ישראל-ה' יקים את זרעו וכסאו של דוד לנצח-בכור ה' יעלה על מלכי הארץ.",
  "Psalms 90": "תפילה של משה, איש האלוהים - אלוהים הוא מעולמי עד - ימי האדם נמשכים אך שבעים שנה - משה מפציר באלוהים לתת רחמים וברכות לעמו.",
  "Psalms 91": "מזמור משיחי - ה' יציל את המשיח מאימה, מגיפה ומלחמה - ה' יתן פקודה למלאכיו על המשיח ויציל אותו ויכבד אותו.",
  "Psalms 92": "מזמור או שיר ליום השבת - הודו לה' - יאבדו אויביו - צדיקים יפרח - אין עוולה בה'.",
  "Psalms 93": "ה' מושל - הוא מעולמי עד - הקדושה מעטרת את בית ה' לעד.",
  "Psalms 94": "ה' ישפוט את הארץ ואת כל בני האדם - אשרי ה' מלמד ומייסר - ה' לא יעזוב את עמו, אלא כרת את הרשעים.",
  "Psalms 95": "הבה נשיר לה' - הבה נעבוד ונשתחוה לפניו - ישראל התגרה באלוהים ולא הצליחה להיכנס למנוחתו.",
  "Psalms 96": "שירו הלל לה' - הכריזו את שמו בין העמים - עבדו את ה' ביופי הקדושה - הוא בא לשפוט את עמו ואת העולם.",
  "Psalms 97": "ה' מושל בתפארת אלפי שנים - הגבעות נמסות בפניו - אלה שאוהבים את ה' שונאים את הרע.",
  "Psalms 98": "שירו לה' - כל קצוות הארץ יראו את ישועתו - הוא בא לשפוט את כל בני האדם ביושר ובצדק.",
  "Psalms 99": "גדול ה' בציון - רוממו את ה' והשתחוו להדום, כי קדוש הוא.",
  "Psalms 100": "עבדו את ה' בשמחה, כל מי שעמו - הודו לו וברכו את שמו.",
  "Psalms 101": "דוד שר רחמים וצדק - הוא יעטש את חברת עושי הרשע.",
  "Psalms 102": "בעל התהילים מציע תפילה של הסובלים - ציון תיבנה כאשר ה' יופיע בכבודו - אף שהשמים והארץ יאבדו, ה' אשר ברא אותם יעמוד לנצח.",
  "Psalms 103": "דוד קורא לקדושים לברך את ה' על רחמיו - ה' רחום לאלה השומרים את מצוותיו.",
  "Psalms 104": "ה' לבוש בכבוד והוד - הוא הופך את מלאכיו לרוחות ולשרתיו לאש בוערת - באמצעות השגחתו הוא מקיים את כל צורות החיים - כבודו נמשך לנצח.",
  "Psalms 105": "הכר את מעשי ה' בכל בני האדם - הראה את בריתו עם אברהם ואת מעשיו עם ישראל - אל תיגע במשוחו, ואל תעשה לנביאיו רע - על ישראל לקיים את חוקיו ולשמור את חוקיו.",
  "Psalms 106": "הלל את ה' על חסדיו ומעשיו האדירים - ישראל מרד ועשה רשעים - משה תיווך בין ישראל וה' - ישראל פוזרה ונהרגה על עבודת אלי שקר.",
  "Psalms 107": "עם ישראל צריך להלל ולהודות לה' כאשר הם נאספים ונגאלים - הו, שאנשים ישבחו את ה'! - השגחת ה' מנצחת בחיי בני אדם.",
  "Psalms 108": "דוד משבח ומעלה את אלוהים - יהודה הוא מחוקק ה'.",
  "Psalms 109": "דוד מדבר על הקללות בשל הרשעים והרמאים - הוא מתפלל שאויביו יתבלבלו.",
  "Psalms 110": "מזמור משיחי לדוד - המשיח ישב לימינו של ה' - הוא יהיה כומר לנצח לפי סדר מלכיצדק.",
  "Psalms 111": "ה' חסד ומלא רחמים - קדוש ומכובד הוא שמו - יראת ה' היא ראשית החכמה.",
  "Psalms 112": "אשרי איש ירא ה' - הצדיק ייזכר תמיד.",
  "Psalms 113": "ברוך שם ה' - מי דומה לה' אלוהינו?",
  "Psalms 114": "ה' מושל בים ובארץ לברכת עמו.",
  "Psalms 115": "אלוהינו בשמים - אלילים הם אלי שקר - בטח בה'.",
  "Psalms 116": "חן ה', וצדיק - יקר בעיני ה' מות קדושיו.",
  "Psalms 117": "הלל את ה' על חסדו ואמתו.",
  "Psalms 118": "מזמור משיחי - יגידו כל ישראל על ה' לעולם חסדיו - האבן שהבונים סרבו הפכה לאבן ראשה של הפינה - ברוך הבא בשם ה'.",
  "Psalms 119": "אשרי מקיימים מצוות.",
  "Psalms 120": "קרא לה' בעת מצוקה.",
  "Psalms 121": "עזרה באה מה' - הוא השומר על ישראל.",
  "Psalms 122": "דוד אומר, לך אל בית ה' - הודו לו.",
  "Psalms 123": "נשא את עיניכם אל ה', והתחננו אליו לרחמים.",
  "Psalms 124": "דוד אומר, עזרת ישראל היא בשם ה'.",
  "Psalms 125": "אשרי הבוטחים בה' - שלום על ישראל.",
  "Psalms 126": "ה' עשה דברים גדולים לעמו ישראל.",
  "Psalms 127": "ילדים הם מורשת מה'.",
  "Psalms 128": "אשרי יראי ה' והולכים בדרכיו.",
  "Psalms 129": "ה' צדיק - יבוהו השונאי ציון.",
  "Psalms 130": "ה', שמע תפילותינו, סלח על העוון וגאל את ישראל.",
  "Psalms 131": "דָּוִד אוֹמֵר, יִקְוָה יִשְׂרָאֵל בַּה' לְעוֹלָם.",
  "Psalms 132": "מזמור משיחי - מפרי חלצי דוד ישים ה' אחד על כסאו - ה' יברך את ציון, וקדושיה יזעקו בשמחה.",
  "Psalms 133": "דוד אומר, נעים לאחים לשבת יחד באחדות!",
  "Psalms 134": "ברך את ה', והוא יברך אותך.",
  "Psalms 135": "הלל וברכו את ה' - אדוננו מעל כל האלים; אלילים אינם יכולים לראות, לשמוע או לדבר.",
  "Psalms 136": "הודו לה' על הכל, כי לעולם חסדו.",
  "Psalms 137": "בעודם בשבי, בכו היהודים ליד נהרות בבל - בגלל הצער, הם לא יכלו לשאת לשיר את שירי ציון.",
  "Psalms 138": "דוד משבח את יהוה על חסד ואמתו האוהבים - הוא משתחווה לבית המקדש הקדוש.",
  "Psalms 139": "דוד אומר שה' יודע את כל מחשבותיו ומעשיו של האדם - הוא שואל, לאן האדם יכול ללכת כדי לברוח מרוחו ומנוכחותו של ה'? - האדם נוצר בצורה מפחידה ומופלאה.",
  "Psalms 140": "דוד מתפלל לישועה מאויביו - ה' מקיים את עניינם של העניים והסובלים.",
  "Psalms 141": "דוד מתחנן בפני ה' שישמע תפילותיו - תוכחת הצדיקים היא חסד.",
  "Psalms 142": "דוד מתפלל לשימור מפני רודפיו.",
  "Psalms 143": "דוד מתפלל לטובה במשפט - הוא מהרהר במעשיו של האדון ובוטח בו.",
  "Psalms 144": "דוד מברך את ה' על הגאולה והשגשוג הזמני - אשרי העם הזה שאלוהיו הוא ה'.",
  "Psalms 145": "דוד מכריז על גדולתו והוד ה' - ה' טוב לכולם - מלכותו היא מלכות נצח - הוא קרוב לכל הקוראים אליו, והוא שומר על האוהבים אותו.",
  "Psalms 146": "מאושרים תקוותם בה' - ה' משחרר את השבויים, אוהב צדיקים וממלוך לנצח.",
  "Psalms 147": "הלל את ה' על כוחו - הבנתו אינסופית - הוא שולח את מצוותיו, דברו, חוקיו ומשפטיו לישראל.",
  "Psalms 148": "יהללו כל הדברים את יהוה: אנשים ומלאכים, גרמי השמים, היסודות והארץ וכל הדברים שעליהם.",
  "Psalms 149": "הלל את ה' בקהילת הקדושים - הוא ייפה את הענווים בישועה.",
  "Psalms 150": "הלל את אלוהים במקדשו - יהללו את ה' כל מה שיש לו נשימה.",
  "Proverbs 1": "יראת ה' היא ראשית הדעת - אם חוטאים יפתו אותך, אל תסכים - השומעים לחוכמה ישכו בבטחה.",
  "Proverbs 2": "ה' נותן חכמה, ידע ותבונה - לכו בדרכם של אנשים טובים.",
  "Proverbs 3": "כתוב רחמים ואמת על לוח לבבך - בטח באלוהים - כבד אותו בחומר שלך - את מי שה' אוהב הוא מתקן - שמח האיש המוצא חוכמה.",
  "Proverbs 4": "שמור את המצוות וחיה - בכל הישגיך, קבל בינה - אל לך בדרכם של רעים.",
  "Proverbs 5": "המתרועעים עם נשים לא מוסריות ירדו לגיהנום - שמח עם אשת נעוריך.",
  "Proverbs 6": "שישה דברים שה' שונא נקראים - אלה הנואפים משמידים את נפשם.",
  "Proverbs 7": "אישה לא מוסרית מובילה אדם לחורבן כשור לטבח - ביתה של אישה נואפת הוא הדרך לגיהנום.",
  "Proverbs 8": "יש רצון רב לחכמה - האדון ובני האדם היו בעלי חוכמה בחיים שלפני המוות.",
  "Proverbs 9": "תוכח באיש חכם והוא יאהב אותך - יראת ה' היא תחילתה של חוכמה - אורחי אישה לא מוסרית נמצאים במעמקי הגיהנום.",
  "Proverbs 10": "בן חכם משמח אב - פי צדיק הוא באר חיים - המוציא לשון הרע הוא שוטה - רצונו של צדיק יינתן.",
  "Proverbs 11": "מצבם וגמולם של הצדיק והרשע מנוגדים - כשאדם רשע מת, ציפיותיו מתכלות - מי שזוכה בנשמות הוא חכם.",
  "Proverbs 12": "אשת סגולה היא כתר לבעלה - דרכו של שוטה ישרה בעיניו - שפתי שקר תועבה לה'.",
  "Proverbs 13": "דרכו של העובר קשה - הרשע רודף חוטאים - מי שאינו משמיע את ילדיו שונא אותם.",
  "Proverbs 14": "לך מפני איש שוטה - עד אמת מציל נפשות - צדק מרומם עם.",
  "Proverbs 15": "תשובה רכה מסיטה את הכעס - בן חכם משמח אב - מחשבות הרשעים תועבה ליהוה - לפני הכבוד באה הענווה.",
  "Proverbs 16": "עדיף לקבל חוכמה מזהב - הגאווה הולכת לפני החורבן - שערו האפור של הצדיק הוא כתר תהילה.",
  "Proverbs 17": "מי ששמח בפורענות ייענש - חבר אוהב בכל עת - אפילו שוטה, כשהוא שותק, נחשב לחכם.",
  "Proverbs 18": "פיו של שוטה הוא ההרס שלו - מי שמשיג אישה משיג דבר טוב - אדם שיש לו חברים חייב להראות את עצמו ידידותי.",
  "Proverbs 19": "אשה נבונה היא מה' - המלווה לעני מלווה לה' - עדיף להיות עני מאשר להיות שקרן.",
  "Proverbs 20": "יין מלגלג, ומשקה חזק משתולל - פנה אל ה', והוא יציל אותך.",
  "Proverbs 21": "עשה צדקה ומשפט - רדפו אחר צדקה ורחמים - בטחון בא מה'.",
  "Proverbs 22": "שם טוב עדיף על עושר - אמנו ילד בדרך שעליו ללכת.",
  "Proverbs 23": "עמל לא להיות עשיר - כמו שאדם חושב בלבו, כך הוא - אל תמנע תיקון מילד - אל תהיה בין שיכורים.",
  "Proverbs 24": "בהמון יועצים יש ביטחון - אל תדאג בגלל אנשים רשעים - זה לא טוב לגלות משוא פנים בשיפוט.",
  "Proverbs 25": "אל תתפאר במתנות שווא - תן אוכל ושתייה לאויבך.",
  "Proverbs 26": "כבוד אינו מתאים לטיפש - אל תענה לטיפש לפי איוולתו - במקום שאין בעל דין, נפסק המריבה.",
  "Proverbs 27": "תן לאדם אחר להלל אותך - אדם נבון צופה את הרע - גיהנום וחורבן לעולם אינם מלאים.",
  "Proverbs 28": "רשעים בורחים כשאין אדם רודף - ההולך ישר יושע - אדם נאמן ישבע ברכות.",
  "Proverbs 29": "כשהרשעים שולטים, העם מתאבל - הצדיקים מתחשבים בעניינו של העני - שוטה מדבר כל אשר בנפשו - במקום שאין חזון, העם מתאבד.",
  "Proverbs 30": "כל דבר אלוהים הוא טהור - אל תן לי לא עוני ולא עושר.",
  "Proverbs 31": "יין ומשקה חזק נידונים - טען בעניין העניים והנזקקים - אשת סגולה יקרה יותר מאבני אודם.",
  "Ecclesiastes 1": "כל דבר תחת השמש הוא הבל ועצבנות רוח - מי שמתרבה בדעת מתגבר בצער.",
  "Ecclesiastes 2": "כל העושר והעושר של המלך הם הבל ועצבנות רוח - חכמה עדיפה על איוולת - אלוהים נותן חוכמה, ידע ושמחה לאדם.",
  "Ecclesiastes 3": "לכל דבר יש עונה - מה שאלוהים יעשה, זה יהיה לנצח - אלוהים ישפוט את הצדיקים והרשעים.",
  "Ecclesiastes 4": "דיכוי ומעשים רעים הם הבל - עדיף כוחם של שניים מאחד - עדיף ילד עני וחכם ממלך זקן וטיפש.",
  "Ecclesiastes 5": "אלוהים בגן עדן - קולו של שוטה ידוע בהמון מילים - שמור את נדריך - עושר ועושר הם מתנת אלוהים.",
  "Ecclesiastes 6": "אלא אם כן נשמתו של אדם מלאה בטוב, עושרו, עושרו, כבודו וצאצאיו הם הבל.",
  "Ecclesiastes 7": "החוכמה נותנת חיים למי שיש אותה - כל בני האדם חוטאים - אלוהים עשה את האדם ישר.",
  "Ecclesiastes 8": "לאף אחד אין כוח להימנע ממוות - לא יהיה טוב לרשעים; הוא פונה להנאה ואינו יכול למצוא חוכמה.",
  "Ecclesiastes 9": "השגחת אלוהים שולטת על הכל - כל בני האדם נתונים לזמן ולמקרה - חכמה עדיפה על כוח - חוטא אחד הורס הרבה טוב.",
  "Ecclesiastes 10": "טיפשות קטנה הורסת את המוניטין של החכם והמכובד - דברי פיו של חכם חסדים - שוטה מלא במילים.",
  "Ecclesiastes 11": "עשה טוב ותן למי שצריך - אלוהים יביא את כל בני האדם למשפט.",
  "Ecclesiastes 12": "בעת המוות תשוב הרוח אל ה' שנתן אותה - דברי חכמים הם כסילים - כל חובתו של האדם היא לירא את ה' ולקיים את מצוותיו.",
  "Song of Solomon 1": "המשורר שר על אהבה ומסירות.",
  "Song of Solomon 2": "אהובים זוכים לשבחים ומתוארים.",
  "Song of Solomon 3": "מובא שיר אהבה הנוגע לשלמה.",
  "Song of Solomon 4": "שיר מתאר את יופייה של אהובתו של המשורר.",
  "Song of Solomon 5": "שיר האהבה והחיבה ממשיך.",
  "Song of Solomon 6": "שיר האהבה ממשיך.",
  "Song of Solomon 7": "שיר האהבה ממשיך.",
  "Song of Solomon 8": "מים רבים אינם יכולים לכבות את האהבה.",
  "Isaiah 1": "עם ישראל כופר, מרדן ומושחת; רק מעטים נשארים נאמנים - זבחי העם ומשתה נדחים - הם נקראים לחזור בתשובה ולעבוד צדקה - ציון תיגאל ביום התקומה.",
  "Isaiah 2": "ישעיהו רואה את בית המקדש של אחרון הימים, כינוס ישראל, משפט ושלום שנות האלפיים - הגאים והרשעים יושפלו בביאה השנייה - השווה נפי ב' 12.",
  "Isaiah 3": "יהודה וירושלים ייענשו על אי-ציותם - ה' מתחנן לשופט את עמו - בנות ציון מקוללות ומתייסרות על עולמיותן - השווה ב' נפי 13.",
  "Isaiah 4": "ציון ובנותיה ייגאלו וינוהרו ביום המילניום - השווה ב' נפי 14.",
  "Isaiah 5": "כרם יהוה (ישראל) יהפוך לשוממה, ואנשיו יתפזרו - יבואו עליהם צער במצבם הכופר והמפוזר - ה' ירים סמל ויאסוף את ישראל - השווה ב' נפי 15.",
  "Isaiah 6": "ישעיהו רואה את האדון - חטאיו נסלחים - הוא נקרא להתנבא - הוא מתנבא על דחיית היהודים את תורתו של ישו - שארית תחזור - השווה נפי ב' 16.",
  "Isaiah 7": "אפרים וסוריה מנהלים מלחמה נגד יהודה - המשיח ייוולד מבתולית - השווה את ב' נפי 17.",
  "Isaiah 8": "המשיח יהיה כאבן מעידה וסלע של פגע - חפש את האדון, לא ממלמל קוסמים - פנה אל החוק ואל העדות להדרכה - השווה את ב' נפי 18.",
  "Isaiah 9": "ישעיהו מדבר על המשיח - העם בחושך יראה אור גדול - לנו נולד ילד - הוא יהיה נסיך השלום וימלוך על כסאו של דוד - השווה נפי ב' 19.",
  "Isaiah 10": "חורבן אשור הוא סוג של חורבן הרשעים בביאה השנייה - מעט אנשים יישארו לאחר שיבוא ה' שוב - שארית יעקב תשוב ביום ההוא - השווה ב' נפי 20.",
  "Isaiah 11": "גזע ישי (המשיח) ישפוט בצדק - הידע על אלוהים יכסה את הארץ במילניום - יהוה יקים סמל ויאסוף את ישראל - השווה נפי ב' 21.",
  "Isaiah 12": "ביום המילניום, כל בני האדם ישבחו את אלוהים - הוא ישכון בתוכם - השווה נפי ב' 22.",
  "Isaiah 13": "חורבן בבל הוא סוג של חורבן בביאה השנייה - זה יהיה יום של זעם ונקמה - בבל (העולם) תיפול לנצח - השווה נפי ב' 23.",
  "Isaiah 14": "ישראל תיאסף ותיהנה ממנוחת אלפי שנים - לוציפר הודח מגן עדן למרד - ישראל תנצח על בבל (העולם) - השווה נפי ב' 24.",
  "Isaiah 15": "מואב תישמד, ואנשיה יבכו ויבכו.",
  "Isaiah 16": "מואב נידונה, ואנשיה יצערו - המשיח ישב על כסאו של דוד, יחפש צדק ויזרז צדקה.",
  "Isaiah 17": "ישראל התפזרה כי שכחה את אלוהים - אך הגויים השודדים אותה ישמדו.",
  "Isaiah 18": "ה' יעלה את סמל הבשורה, ישלח שליחים לעמו המפוזר ויאסוף אותם להר ציון.",
  "Isaiah 19": "ה' יכה וישמיד את מצרים - לבסוף ירפא אותה, ומצרים ואשור יתברכו עם ישראל.",
  "Isaiah 20": "אשור תכריע את מצרים ותבייש אותה.",
  "Isaiah 21": "בבל נפלה, נפלה! - גם עמים אחרים נהרסו.",
  "Isaiah 22": "ירושלים תותקף ותוכה - העם יישא בשבי - המשיח יחזיק מפתח בית דוד, יירש תהילה ויהודק כמסמר במקום בטוח.",
  "Isaiah 23": "צמיג יופל.",
  "Isaiah 24": "בני אדם יעברו על החוק ויפרו את הברית הנצחית - בביאה השנייה הם ישרפו, האדמה תרד, והשמש תתבייש - אז ימלוך ה' בציון ובירושלים.",
  "Isaiah 25": "בהר ציון יכין ה' חג בשורה של אוכל עשיר - יבלע את המוות בניצחון - ייאמר, הנה זה אלוהינו.",
  "Isaiah 26": "בטח בה' לנצח - יהוה ימות ויקום לתחייה - כל בני האדם יקומו בתחיית המתים.",
  "Isaiah 27": "עם ישראל יפרח ויפרח וימלא את הארץ בפרי - יאספו אחד אחד ויעבדו את ה'.",
  "Isaiah 28": "אוי לשיכורי אפרים!-ההתגלות באה שורה על שורה ומצוה על מצוה - המשיח, היסוד הבטוח, מובטח.",
  "Isaiah 29": "עם (הנפים) ידבר כקול מהעפר - הכפירה, שיקום הבשורה ויציאתו של ספר חתום (ספר מורמון) צפויים - השווה נפי ב' 27.",
  "Isaiah 30": "ישראל מפוזר בשל דחיית הרואים והנביאים - עם ישראל יתאסף ויבורך בזמני וברוחני - ה' יבוא ביום כפירה לשפוט ולהשמיד את הרשעים.",
  "Isaiah 31": "ישראל ננזף על כך שהם פונים למצרים לעזרה - בבוא ה', הוא יגן וישמור על עמו.",
  "Isaiah 32": "מלך (המשיח) ימלוך בצדק - ארץ ישראל תהיה מדבר עד יום השיקום והכינוס.",
  "Isaiah 33": "כפירה ורשע יקדמו לביאה השנייה - ה' יבוא באש אוכלת - ציון ויתדותיה ישתלמו - ה' הוא השופט, המחוקק והמלך שלנו.",
  "Isaiah 34": "הבא השני יהיה יום של נקמה ומשפט - זעם ה' יהיה על כל העמים - חרבו תיפול על העולם.",
  "Isaiah 35": "ביום השיקום יפרח המדבר, ה' יבוא, ישראל ייקנס, וציון תיבנה.",
  "Isaiah 36": "האשורים נלחמים ביהודה ומגדף את ה'.",
  "Isaiah 37": "חזקיהו מבקש עצה מישעיהו להציל את ירושלים - ישעיהו מנבא את תבוסת האשורים ואת מותו של סנחריב - חזקיהו מתפלל לישועה - סנחריב שולח מכתב חילול הקודש - ישעיהו מנבא שהאשורים ייחרדו וששארית מיהודה תהרוג 500 מלאך - 800 מלאך. אשורים - סנחריב נהרג על ידי בניו.",
  "Isaiah 38": "חייו של חזקיהו מתארכים חמש עשרה שנים - השמש חוזרת עשר מעלות לאות - חזקיהו משבח ומודה לה'.",
  "Isaiah 39": "חזקיהו מגלה לבבל את עושרו - ישעיהו מנבא את השבי הבבלי.",
  "Isaiah 40": "ישעיהו מדבר על המשיח - הכן את דרך ה' - הוא ירזה את צאנו כרועה צאן - אלוהי ישראל גדול מאין כמותו.",
  "Isaiah 41": "לישראל אומר ה', עבדי אתם; אני אשמור עליך - אלילים הם כלום - אחד יביא בשורה טובה לירושלים.",
  "Isaiah 42": "ישעיהו מדבר על המשיח - ה' יביא את תורתו ואת צדקתו, יהיה אור לגויים וישחרר את האסירים - הלל את ה'.",
  "Isaiah 43": "לישראל אומר ה', אני אלהיך; אאסוף את צאצאיך; לצידי אין מושיע; אתם העדים שלי.",
  "Isaiah 44": "רוח ה' תישפך על צאצאיהם של ישראל - אלילי עץ הם כדלק למדורה - ה' יאסוף, יברך ויגאל את ישראל ויבנה מחדש את ירושלים.",
  "Isaiah 45": "כורש ישחרר את שבויי ישראל מבבל - בוא אל יהוה (המשיח) ויושע - אליו תכרע כל ברך וכל לשון תישבע.",
  "Isaiah 46": "אין להשוות אלילים עם ה' - הוא לבדו הוא אלוהים ויציל את ישראל.",
  "Isaiah 47": "בבל וכלדיה יושמדו על עוונותיהם - איש לא יציל אותם.",
  "Isaiah 48": "יהוה מגלה את מטרותיו לישראל - ישראל נבחרה בכבשן הסבל והיא תסתלק מבבל - השווה לנפי א' 20.",
  "Isaiah 49": "המשיח יהיה אור לגויים וישחרר את האסירים - ישראל תיאסף בכוח באחרית הימים - המלכים יהיו האבות המיניים של ישראל - השווה א' נפי כ\"א.",
  "Isaiah 50": "ישעיהו מדבר כמשיח - תהיה לו לשון המשכילים - הוא ייתן את גבו למכותים - הוא לא יתבלבל - השווה ב' נפי 7.",
  "Isaiah 51": "באחרית הימים ה' ינחם את ציון ויקבץ את ישראל - הגואלים יבואו לציון בשמחה גדולה - השווה ב' נפי ח'.",
  "Isaiah 52": "באחרית הימים תשוב ציון, וישראל יגאלו - המשיח ינהג בתבונה ויתעלה.",
  "Isaiah 53": "ישעיהו מדבר על המשיח - השפלתו ויסוריו מתוארים - הוא עושה את נפשו מנחה לחטא ומשתדל למען העוברים - השוו את משה י\"ד.",
  "Isaiah 54": "באחרית הימים יתבססו ציון ויתדותיה, וישראל יתאספו ברחמים ורוך - ישראל תנצח - השווה ג' נפי כ\"ב.",
  "Isaiah 55": "בואו לשתות; הישועה בחינם - ה' יכרה ברית עולם עם ישראל - חפש את ה' כשהוא קרוב.",
  "Isaiah 56": "כל השומרים מצוות יתנשאו - אנשים אחרים יצטרפו לישראל - ה' יאסוף אחרים לבית ישראל.",
  "Isaiah 57": "כשהצדיקים מתים, הם נכנסים לשלום - רחמים מובטחים לחוזר בתשובה - אין שלום לרשעים.",
  "Isaiah 58": "חוק הצום האמיתי, על מטרותיו וברכותיו הנלוות, נקבע - ניתנת מצוות שמירת השבת.",
  "Isaiah 59": "עם ישראל מופרד מאלוהיו על ידי עוון - חטאיו מעידים עליו - המשיח יתערב, יבוא לציון ויגאל את החוזרים בתשובה.",
  "Isaiah 60": "באחרית הימים יקום ישראל שוב כעם אדיר - העמים הגויים יצטרפו לישראל ויעבדו - תקום ציון - לבסוף ישכון ישראל בפאר שמיימי.",
  "Isaiah 61": "ישעיהו מדבר על המשיח - למשיח תהיה הרוח, יכריז את הבשורה ויכריז על חירות - באחרית הימים, יקרא ה' את שריו ויכרות ברית נצח עם העם.",
  "Isaiah 62": "באחרית הימים יתאספו ישראל - תקום ציון - שומריה ילמדו על ה' - יורם תקן הבשורה - העם ייקרא קדוש, גאולי ה'.",
  "Isaiah 63": "הבא השני יהיה יום של נקמה וגם שנת הגאולה של האדון - ואז הקדושים ישבחו את האדון ויכירו בו כאביהם.",
  "Isaiah 64": "אנשי ה' מתפללים לביאה השנייה ולישועה שתהיה אז שלהם.",
  "Isaiah 65": "ישראל הקדומה נדחתה בגלל שדחתה את יהוה - עם יהוה ישמח וינצח במהלך המילניום.",
  "Isaiah 66": "בביאה השנייה, ישראל, כעם, יוולד ביום; רשעים ישמדו; והגוים ישמעו את הבשורה.",
  "Jeremiah 1": "ירמיהו נקבע מראש להיות נביא לגויים - הוא נקרא כבן תמותה להכריז את דבר ה'.",
  "Jeremiah 2": "בני יהודה עזבו את ה', מעיין המים החיים - הם עבדו לאלילים ודחו את הנביאים.",
  "Jeremiah 3": "ישראל ויהודה טמאו וזיהמו את הארץ ברשע - באחרית הימים יאסוף ה' את עם ישראל אחד מעיר ושניים ממשפחה ויביא אותם לציון.",
  "Jeremiah 4": "ישראל ויהודה נקראים לחזור בתשובה - ירמיהו מקונן על אומללות יהודה.",
  "Jeremiah 5": "משפטים ישפכו על בני יהודה בגלל חטאיהם - עוונותיהם גורמים למניעת ברכות מהם.",
  "Jeremiah 6": "ירושלים תיהרס בגלל עוונותה - היא תוכרע על ידי אומה גדולה ואכזרית.",
  "Jeremiah 7": "אם בני יהודה יחזרו בתשובה, הם ישמרו - בית המקדש הפך למאורת שודדים - ה' דוחה את הדור ההוא של בני יהודה בשל עבודת האלילים שלהם - הם מקריבים את ילדיהם כקורבנות.",
  "Jeremiah 8": "אסונות יבואו על תושבי ירושלים - עבורם עבר הקציר, הקיץ תם, והם לא ניצלו.",
  "Jeremiah 9": "ירמיהו מצטער מאוד על חטאי העם - הם יתפזרו בין העמים ויענשו.",
  "Jeremiah 10": "אל תלמדו את דרכם של עמים אחרים - האלים שלהם אלילים וצלמים מותכים - ה' הוא האל האמיתי והחי.",
  "Jeremiah 11": "בני יהודה מקוללים על כך שהם מפרים את ברית הציות - ה' לא ישמע לתפילותיהם.",
  "Jeremiah 12": "ירמיהו מתלונן על שגשוג הרשעים - אם ילמדו עמים אחרים את דרכי ישראל, הם ייספרו עם ישראל.",
  "Jeremiah 13": "ישראל ויהודה יהיו כחגורה נרקבת ונרקבת - העם מצווה לחזור בתשובה - יהודה יילקח בשבי ותפזר כזיפים.",
  "Jeremiah 14": "ירמיהו מתפלל בגלל מחסור ורעב - ה' לא ישמע בגלל רשעות עמו.",
  "Jeremiah 15": "בני יהודה יסבלו מוות, חרב, רעב ושבי - הם יתפזרו בכל ממלכות הארץ - ירושלים תושמד.",
  "Jeremiah 16": "חורבה המוחלט של יהודה צפויה מראש - ישראל נדחית ומתפזרת בשל שירות אלי שקר - דייגים וציידים יאספו שוב את ישראל, והעם ישרת את ה' - יש להחזיר את הבשורה.",
  "Jeremiah 17": "שבי יהודה בא בגלל החטא והפקרת ה' - קדש את יום השבת; פעולה זו תציל את העם; אחרת הם יושמדו.",
  "Jeremiah 18": "ישראל הם כחמר חרס בידי ה' - אם גוים יחזרו בתשובה, ה' ימנע את הרע שנגזר עליהם - בני יהודה יתפזרו.",
  "Jeremiah 19": "ה' יביא רעה על יהודה - הם מקריבים את בניהם לבעל - במצור יאכלו את בשר בניהם ובנותיהם.",
  "Jeremiah 20": "ירמיהו מוכה ומוכנס למלאי - הוא מנבא שכל יהודה תילקח בשבי בבל.",
  "Jeremiah 21": "ירמיהו מנבא את המצור, השבי והחורבן של ירושלים - צדקיהו יילקח בשבי על ידי נבוכדרצר.",
  "Jeremiah 22": "כס דוד עומד או נופל לפי ציות המלכים - משפטי ה' מונחים על מלכי יהודה.",
  "Jeremiah 23": "שאריות ישראל יתאספו באחרית הימים - הענף שהוא המלך (המשיח) ימלוך בצדק - נביאי שקר המלמדים שקר יקוללו.",
  "Jeremiah 24": "צדקיהו ועם יהודה יקוללו ויתפזרו - חלקם יאספו חזרה מכלדיה לעבוד את ה'.",
  "Jeremiah 25": "יהודה השבוי ישרת את בבל שבעים שנה - גוים שונים יופלו - באחרית הימים, כל יושבי הארץ יהיו במלחמה.",
  "Jeremiah 26": "ירמיהו מנבא את השמדת העם - על כך הוא מועמד לדין, נשפט ואז זוכה.",
  "Jeremiah 27": "ה' שולח הודעה לעמים רבים שהם צריכים לעבוד את בבל - כלי בית ה' יכנסו לבבל.",
  "Jeremiah 28": "חנניה מנבא בשקר שהעול הבבלי יישבר.",
  "Jeremiah 29": "ירמיהו אומר ליהודים בבבל להתכונן לשבעים שנות שבי - הנשארים בירושלים עוד יתפזרו - שמעיה מנבא שקר ומקולל.",
  "Jeremiah 30": "באחרית הימים יתאספו יהודה וישראל לארצם - דוד מלכם (המשיח) ימלוך עליהם.",
  "Jeremiah 31": "באחרית הימים יתאספו ישראל - ה' מכריז כי לאפרים יש הבכורה כבכור - ה' יכרה ברית חדשה עם ישראל שתירשם בלב - אז יכירו כל ישראל את ה'.",
  "Jeremiah 32": "ירמיהו נכלא על ידי צדקיהו - הנביא רוכש אדמה כדי לסמל את שיבת ישראל לארצם - ה' יאסוף את ישראל ויכרות עמם ברית עולם.",
  "Jeremiah 33": "יהודה וישראל ייאספו - ענף הצדק (המשיח) מובטח - זרע דוד (המשיח) ימלוך לעד.",
  "Jeremiah 34": "ירמיהו מנבא את שבי צדקיהו - בני יהודה יוסרו לכל ממלכות הארץ.",
  "Jeremiah 35": "הרקאבים זוכים לשבח ומבורכים על ציותם.",
  "Jeremiah 36": "ברוך כותב את נבואות ירמיהו וקורא אותן בבית ה' - יהויקים המלך שורף את הספר ובא עליו הדין - ירמיהו מכתיב שוב את הנבואות ומוסיף עוד רבות.",
  "Jeremiah 37": "ירמיהו מנבא שמצרים לא תציל את יהודה מבבל - הוא מושלך לצינוק - צדקיהו מעביר אותו לחצר הכלא.",
  "Jeremiah 38": "השליטים השליכו את ירמיהו לתוך צינוק בוצי - הוא משוחרר על ידי עבד-מלך, אתיופי, ומוכנס לחצר הכלא - ירמיהו מייעץ לצדקיה באשר למלחמה.",
  "Jeremiah 39": "ירושלים נלקחת, והעם נשבה - ירמיהו ועבד-מלך, האתיופי, נשמרים.",
  "Jeremiah 40": "מלך בבל מעמיד את גדליה למושל על השארית שנותרה ביהודה - ירמיהו משתחרר ומתגורר בתוכם.",
  "Jeremiah 41": "ישמעאל הורג את גדליה ונושא את אנשי מצפה בשבי - הם ניצלים על ידי יוחנן.",
  "Jeremiah 42": "ירמיהו מבטיח ליוחנן ולשארית יהודה שלום וביטחון אם יישארו ביהודה, אך חרב, רעב ומגפה אם ילכו למצרים.",
  "Jeremiah 43": "יוחנן נושא את ירמיהו ושארית יהודה למצרים - ירמיהו מנבא שבבל תכבוש את מצרים.",
  "Jeremiah 44": "ירמיהו מנבא שהיהודים במצרים, מלבד שריד קטן, יושמדו בגלל שהם סוגדים לאלי שקר.",
  "Jeremiah 45": "ירמיהו מבטיח לברוך שחייו יישמרו.",
  "Jeremiah 46": "ירמיהו מנבא את כיבוש מצרים על ידי בבל - יעקב יינצל וישוב לארצו.",
  "Jeremiah 47": "ירמיהו מנבא שממה וחורבן על הפלשתים.",
  "Jeremiah 48": "משפט וחורבן יבואו על המואבים על בוז ה'.",
  "Jeremiah 49": "משפט וחורבן יבואו על אנשי עמון, אדום, קדר, חצור ועלם.",
  "Jeremiah 50": "בבל תושמד ולא תקום עוד - עם ישראל המפוזר יובא שוב אל ארצות נחלתו.",
  "Jeremiah 51": "משפט, חורבן ושממה יבואו על בבל על חטאיה - מצווה על ישראל, ברח מבבל - ישראל היא מטה ה' להשמיד את כל הממלכות.",
  "Jeremiah 52": "ירושלים נצורה ונכבשה על ידי הכשדים - אנשים רבים וכלי בית ה' נישאים לבבל.",
  "Lamentations 1": "ירמיהו מבכה את מצבה העגום של ירושלים - ירושלים עצמה מתלוננת על צערה העמוק.",
  "Lamentations 2": "סבל, צער ושממה שוררים בירושלים.",
  "Lamentations 3": "ירמיהו, מדבר בשם יהודה, מקונן על הפורענות אך בוטח באלוהים ומתפלל לישועה.",
  "Lamentations 4": "מצבה של ציון מעורר רחמים בגלל החטא והעוון.",
  "Lamentations 5": "ירמיהו קורא בתפילה את מצבה העגום של ציון.",
  "Ezekiel 1": "יחזקאל רואה בחזון ארבעה יצורים חיים, ארבעה גלגלים וכבוד אלוהים על כסאו.",
  "Ezekiel 2": "יחזקאל נקרא לקחת את דבר ה' לישראל - הוא רואה ספר שבו כתובות קינות ואבל.",
  "Ezekiel 3": "יחזקאל נעשה שומר לבית ישראל - דם ישראל נדרש בידו אלא אם כן ירים את קול האזהרה.",
  "Ezekiel 4": "יחזקאל ממחיש באופן סמלי את המצור והרעב שיפקדו את ירושלים.",
  "Ezekiel 5": "משפט ירושלים יכלול רעב, מגיפה, מלחמה ופיזור יושביה.",
  "Ezekiel 6": "עם ישראל יושמד על עבודת האלילים שלו - שריד רק ייוושע ותפוזר.",
  "Ezekiel 7": "שממה, מלחמה, מגיפה וחורבן יסחפו את ארץ ישראל - שממת העם צפויה מראש.",
  "Ezekiel 8": "יחזקאל רואה בחזון את הרוע והתועבות של בני יהודה בירושלים - הוא רואה עבודת אלילים נהוגה בבית המקדש עצמו.",
  "Ezekiel 9": "יחזקאל רואה את סימון הצדיקים ואת שחיטת כל האחרים, החל מקודש ה'.",
  "Ezekiel 10": "הוא רואה בחזון, כמו קודם, את הגלגלים, את הכרובים ואת הכסא ואת כבוד ה'.",
  "Ezekiel 11": "הוא רואה בחזון את חורבן ירושלים ואת שבי היהודים - הוא מנבא את כינוס ישראל באחרית הימים.",
  "Ezekiel 12": "יחזקאל הופך את עצמו לסמל לפיזורם של בני יהודה מירושלים - לאחר מכן הוא מנבא את פיזורם בין כל העמים.",
  "Ezekiel 13": "יחזקאל מוכיח נביאי שקר, זכר ונקבה, המדברים שקר, שאלוהים לא דיבר אליהם.",
  "Ezekiel 14": "ה' לא יענה למי שעובדים לאלי שקר ועושים עוון - יחזקאל מטיף לתשובה - העם לא יינצל אם נח, דניאל ואיוב ישרתו בתוכם.",
  "Ezekiel 15": "ירושלים, כגפן חסרת תועלת, תישרף.",
  "Ezekiel 16": "ירושלים הפכה לזונה, מתענגת על אליליה ועובדת לאלי שקר - היא השתתפה בכל חטאי מצרים והגוים מסביב, והיא נדחתה - אולם באחרית הימים, ה' ישוב ויקים את בריתו עמה.",
  "Ezekiel 17": "יחזקאל מראה במשל כיצד ישראל, בעודם כפופים לבבל, ביקשו עזרה ממצרים שלא כדין - אך ה' יוציא באחרית הימים עץ יפה מארז הלבנון.",
  "Ezekiel 18": "בני אדם ייענשו על חטאיהם - חוטאים ימותו, והצדיקים יחיו בוודאי - צדיק שיחטא ייחרד, וחוטא שיחזור בתשובה ייוושע.",
  "Ezekiel 19": "יחזקאל מקונן על ישראל כי היא נשבה על ידי עמים אחרים ונעשתה כגפן נטועה באדמה יבשה וצמאה.",
  "Ezekiel 20": "מאז יציאתם ממצרים ועד ליום יחזקאל, עם ישראל מרד ולא הצליח לקיים את המצוות - באחרית הימים, ה' יאסוף את ישראל וישיב את ברית הבשורה שלו.",
  "Ezekiel 21": "גם צדיקים וגם רשעים בירושלים יהרגו - בבל תשלוף חרב חדה ובהירה על ישראל ותגבר.",
  "Ezekiel 22": "יחזקאל מקטלג את חטאי בני יהודה בירושלים - הם יפוצו וישמדו על עוונותיהם.",
  "Ezekiel 23": "שתי אחיות, שומרון וירושלים, ביצעו זנות על ידי סגידה לאלילים - שתיהן מושמדות בגלל זימתן.",
  "Ezekiel 24": "גזר הדין הבלתי הפיך של ירושלים צפוי מראש - כאות ליהודים, יחזקאל אינו בוכה על מות אשתו.",
  "Ezekiel 25": "נקמת יהוה תיפול בעמוני, במואב ובאדומי ובפלשתים.",
  "Ezekiel 26": "בגלל ששמחה בצער ובנפילה של ירושלים, צור תיהרס.",
  "Ezekiel 27": "יחזקאל מקונן על נפילת צור ואובדן עושרה ומסחרה.",
  "Ezekiel 28": "צור וצידון יפלו וישמדו - ה' יאסוף את עם ישראל לארצו - אז הם ישכו בבטחה.",
  "Ezekiel 29": "מצרים תופל על ידי בבל - כאשר מצרים תקום שוב, היא תהיה הממלכות השפלה ביותר.",
  "Ezekiel 30": "מצרים ועוזריה ישממו על ידי בבל.",
  "Ezekiel 31": "תהילתו ונפילתו של פרעה מושווים לזה של האשורים.",
  "Ezekiel 32": "יחזקאל קונן על נפילת פרעה ומצרים.",
  "Ezekiel 33": "שומרים שמרימים את קול האזהרה מצילים את נפשם שלהם - חוטאים חוזרים בתשובה ניצלים - צדיקים שפונים לחטא ארורים - אנשי יהודה בירושלים נהרסים בגלל חטאיהם.",
  "Ezekiel 34": "ה' מוכיח את אותם רועים שאינם מרזים את הצאן - באחרית הימים, ה' יאסוף את צאן ישראל האבודים - המשיח יהיה הרועה שלהם - ה' יכרות עמם את ברית הבשורה שלו.",
  "Ezekiel 35": "משפט יפול על הר שעיר ועל כל אדומיאה על שנאת ישראל.",
  "Ezekiel 36": "באחרית הימים יתאספו כל בית ישראל לארצם - ה' יתן להם לב חדש ורוח חדשה - תהיה להם חוק הבשורה שלו.",
  "Ezekiel 37": "יחזקאל מוצג עמק העצמות היבשות - ישראל תירש את הארץ בתחיית המתים - מקל יהודה (התנ\"ך) ומקל יוסף (ספר מורמון) יהפכו לאחד ביד ה' - בני ישראל יתאספו וינוהרו - דוד (המשיח) ימלוך עליהם - הם יקבלו את ברית הנצח.",
  "Ezekiel 38": "קרב גוג, מארץ מגוג, נגד ישראל, יביא לביאה השנייה - ה' יבוא בתוך מלחמה ומגפה, וכל האנשים ירעדו בפניו.",
  "Ezekiel 39": "גוג וארץ מגוג יחרבו - שבע שנים ישרפו העם בערי ישראל את כלי המלחמה - שבעה חודשים יקברו את המתים - אז תבוא סעודת האל הגדול והמשך כינוס ישראל.",
  "Ezekiel 40": "שליח שמימי מראה ליחזקאל בחזון עיר שבה ממוקם המקדש - יחזקאל מוצגת צורתו וגודלו של המקדש וחצרותיו.",
  "Ezekiel 41": "יחזקאל רואה את בית המקדש הפנימי ואת קודש הקדשים, ומראים לו את צורתם וגודלם.",
  "Ezekiel 42": "יחזקאל רואה בבית המקדש את חדרי הכהנים.",
  "Ezekiel 43": "כבוד ה' ממלא את בית המקדש - כסאו שם, והוא מבטיח לשבת בקרב ישראל לנצח - יחזקאל רואה את המזבח ואת תקנות המזבח.",
  "Ezekiel 44": "כבוד ה' ממלא את בית ה' - אין להיכנס זרים אל הקודש - מוסברות שירותי הכהנים בבית המקדש.",
  "Ezekiel 45": "חלקי אדמה יסופקו למקדש ולמגורי הכהנים - העם יקריב את זבחיו ומנחותיו ויערוך את חגיו.",
  "Ezekiel 46": "מבוארים תקנות הפולחן והקורבן.",
  "Ezekiel 47": "מים יוצאים מבית ה' ומרפאים את ים המלח - ה' מראה את גבולות הארץ.",
  "Ezekiel 48": "חלקי האדמה לשבטים נקראים - שערי העיר נושאים את שמות השבטים - שם העיר יהיה ה' שם.",
  "Daniel 1": "דניאל ועברים מסוימים מאומנים בחצר נבוכדנצר - הם אוכלים אוכל פשוט ולא שותים יין - אלוהים נותן להם ידע וחוכמה מעבר לכל השאר.",
  "Daniel 2": "חלומו של נבוכדנצר מתגלה לדניאל - המלך ראה צלם גדול, אבן שנכרתה מההר ללא ידיים הרסה את הצלם, והאבן גדלה ומלאה את כל הארץ - האבן היא מלכות אלוהים של אחרון הימים.",
  "Daniel 3": "נבוכדנצר יוצר תמונת זהב ומצווה על כל בני האדם לעבוד אותו - שדרך, משך ועבד-נגו מסרבים ומושלכים לכבשן האש - הם נשמרים ויוצאים ללא פגע.",
  "Daniel 4": "דניאל מפרש את חלומו של נבוכדנצר על העץ הגדול, מתאר את נפילת המלך ושיגעונו - המלך לומד שהעליון שולט ומציב את הנבדל שבבני אדם על ממלכות ארציות.",
  "Daniel 5": "בלשאצר וחוגגיו שותים מכלי המקדש - יד כותבת על הקיר, מספרת על נפילתו של בלשאצר - דניאל מפרש את הדברים ומוכיח את המלך על גאווה ועבודת אלילים - בלילה ההוא נכבשת בבל.",
  "Daniel 6": "דריוש הופך את דניאל לראשון הנשיאים שלו - דניאל עובד את ה' בניגוד לגזירת דריוש - הוא מושלך לגוב האריות - אמונתו מצילה אותו, ודריוש קובע שכל האנשים יכבדו את אלוהי דניאל.",
  "Daniel 7": "דניאל רואה ארבע חיות המייצגות את ממלכות בני האדם - הוא רואה את קדמון הימים (אדם) שאליו יבוא בן האדם (המשיח) - המלכות תינתן לקדושים לנצח.",
  "Daniel 8": "דניאל רואה בחזון איל (מדיה ופרס), עז (יוון), עוד ארבעה מלכים, ולאחר מכן, באחרית הימים, מלך אכזרי שישמיד את העם הקדוש - המלך הזה ישבר כשיעמוד מול נסיך הנסיכים.",
  "Daniel 9": "דניאל צם, מתוודה ומתפלל עבור כל ישראל - גבריאל מגלה את זמן ביאת המשיח, אשר יעשה פיוס על עוון - המשיח ייכרת.",
  "Daniel 10": "דניאל רואה את האדון ואחרים בחזון מפואר - מראים לו את מה שעתיד להיות באחרית הימים.",
  "Daniel 11": "דניאל רואה את המלכים הרצופים ואת המלחמות, הליגות והעימותים שלהם שמובילים לביאתו השנייה של ישו.",
  "Daniel 12": "באחרית הימים, מיכאל יציל את ישראל מצרותיהם - דניאל מספר על שתי תחיית המתים - החכמים יידעו את הזמנים והמשמעויות של חזיונותיו.",
  "Hosea 1": "הושע ומשפחתו הם אות לישראל - ביום הכינוס יהפוך עם ישראל לבני אלוהים חיים.",
  "Hosea 2": "סגידה לאלי שקר מביאה משפטים קשים על ישראל - באחרית הימים, ישראל יתפייסו עם אלוהים ויהפכו לעמו.",
  "Hosea 3": "יבקשו ישראל את ה', יחזרו אל ה' ויקבלו מטובו באחרית הימים.",
  "Hosea 4": "ישראל מאבדים את כל האמת, הרחמים והידע של אלוהים ומזנות אחרי אלוהי שקר.",
  "Hosea 5": "ממלכות יהודה וישראל יפלו שתיהן בגלל עוונותיהן.",
  "Hosea 6": "הושע קורא לישראל לשוב ולעבוד את ה' - הרחמים והכרת ה' חשובים יותר מקרבנות פולחניים.",
  "Hosea 7": "ישראל ננזף על חטאיה הרבים - אפרים מעורב בעם.",
  "Hosea 8": "גם ישראל וגם יהודה עזבו את ה' - ה' כתב את גדולי תורתו לאפרים.",
  "Hosea 9": "עם ישראל נלקח בשבי על חטאיו - אפרים יהיה נודד בין העמים.",
  "Hosea 10": "ישראל חרשו רשעות וקצרו עוון - הושע קורא לישראל לבקש את ה'.",
  "Hosea 11": "ישראל, כילד, נקרא ממצרים בדמותו של אדוננו, כילד, יוצא ממצרים - אבל אפרים מתרחק מה'.",
  "Hosea 12": "ה' משתמש בנביאים, בחזיונות ובדמיונות כדי להדריך את עמו, אך הם מתעשרים ולא יחכו לה' - אפרים מתגרה בו ביותר.",
  "Hosea 13": "חטאיו של אפרים מגרים את ה' - אין מושיע מלבד ה' - הוא פודה מהקבר וגואל ממוות.",
  "Hosea 14": "באחרית הימים, אפרים יחזור בתשובה וישוב אל ה'.",
  "Joel 1": "קראו עצרת ותאספו אל בית ה', כי קרוב יום ה'.",
  "Joel 2": "מלחמה ושממה יקדמו לביאה השנייה - השמש והירח יחשכו - ה' ישפוך את רוחו על כל בשר - יהיו חלומות וחזיונות.",
  "Joel 3": "כל העמים יהיו במלחמה - המונים יעמדו בעמק ההכרעה כשהביאה השנייה מתקרבת - ה' ישכון בציון.",
  "Amos 1": "עמוס מראה את משפטי ה' על סוריה, הפלשתים, צור, אדום ועמון.",
  "Amos 2": "ה' ישפוך משפטים על מואב, יהודה וישראל על עוונותם.",
  "Amos 3": "ה' מגלה את סודותיו לעבדיו הנביאים - מכיוון שישראל דוחים את הנביאים והולכים אחרי הרע, העם מוצף על ידי יריב.",
  "Amos 4": "יהוה מונע גשם, שולח רעב ומגפה, ומשמיד גנים וכרמים כמשפטים על עמו, אך הם אינם שבים אל ה'.",
  "Amos 5": "עם ישראל קורא לבקש את ה' ולעשות טוב כדי שיחיו - הקורבנות שלהם לאלי שקר מתועבים.",
  "Amos 6": "אוי להם לנוח בציון - ישראל תהיה נגועה בשממה.",
  "Amos 7": "עמוס מספר כיצד הוא נקרא מאלוהים להיות נביא - הוא מנבא את שבי ישראל.",
  "Amos 8": "עמוס מנבא את נפילת ישראל - יהיה רעב לשמוע את דבר ה'.",
  "Amos 9": "ישראל ינופה בין כל העמים - באחרית הימים, עם ישראל יתאסף שוב לארצו, והיא תהפוך ליצרנית.",
  "Obadiah 1": "עובדיה מנבא את נפילת אדום - מושיעים יעמדו על הר ציון.",
  "Jonah 1": "יונה נשלח לקרוא לנינוה לחזור בתשובה - הוא בורח על ספינה, מושלך לים, ונבלע על ידי דג גדול.",
  "Jonah 2": "יונה מתפלל לאלוהים, והדג מקיא אותו על אדמה יבשה.",
  "Jonah 3": "יונה מנבא את נפילת נינוה - העם חוזר בתשובה, והעיר ניצלת.",
  "Jonah 4": "יונה לא מרוצה מה' על רחמיו על העם - ה' נוזף בו.",
  "Micah 1": "מיכה מנבא את נפילת השומרון וירושלים.",
  "Micah 2": "חורבן ישראל מקונן - ה' יאסוף את שארית ישראל.",
  "Micah 3": "כוהנים שמלמדים בשכר ונביאים המתלוננים תמורת כסף מביאים קללה על העם.",
  "Micah 4": "באחרית הימים יבנה בית המקדש, יתאספו אליו ישראל, יתחיל עידן המילניום, וה' ימלוך בציון.",
  "Micah 5": "המשיח ייוולד בבית לחם - באחרית הימים, שארית יעקב תנצח בכבוד על הגויים.",
  "Micah 6": "למרות כל טובו כלפיהם, העם לא שירת את ה' ברוח ובאמת - עליהם לנהוג בצדק, לאהוב רחמים וללכת בענווה לפניו.",
  "Micah 7": "אף על פי שעם ישראל מרד, בכל זאת באחרית הימים ה' ירחם עליהם - ירחם ויסלח על עוונותיהם.",
  "Nahum 1": "נחום מדבר על שריפת הארץ בביאה השנייה ועל רחמיו וכוחו של ה'.",
  "Nahum 2": "נינוה תושמד, שהיא סמל למה שיהיה באחרית הימים.",
  "Nahum 3": "הנפילה האומללה של נינווה צפויה מראש.",
  "Habakkuk 1": "כאשר נודע לחבקוק שה' יקים את הכשדים כדי להשתלט על ארץ ישראל, הוא מוטרד מכך שניתן להעסיק כך את הרשעים.",
  "Habakkuk 2": "האדון מעודד סבלנות ומבטיח שהצדיק יחיה באמונה - הארץ תתמלא בידע על אלוהים - לאלילים אין כוח.",
  "Habakkuk 3": "בתפילתו חבקוק רועד לכבוד ה'.",
  "Zephaniah 1": "חורבן יהודה הוא סמל לביאה השנייה - זה יום קורבן ה', יום של זעם וצרה.",
  "Zephaniah 2": "חפש צדקה; חפש ענווה - יבוא משפט על הפלשתים, המואבים, בני עמון, האתיופים והאשורים.",
  "Zephaniah 3": "בביאה השנייה, כל העמים יתאספו לקרב - לבני אדם תהיה שפה טהורה - ה' ימלוך בקרבם.",
  "Haggai 1": "חגי קורא לעם לבנות את בית המקדש.",
  "Haggai 2": "חגי מדבר על המשיח - רצון כל העמים יבוא - ה' יתן שלום במקדשו.",
  "Zechariah 1": "זכריה קורא ליהודה לחזור בתשובה - הוא מוצג בחזון שערי יהודה ובית המקדש ייבנו מחדש.",
  "Zechariah 2": "באחרית הימים יהודה תתכנס לירושלים - העם יבוא מארץ הצפון - ה' ישכון בתוכם.",
  "Zechariah 3": "זכריה מדבר על המשיח - הענף יבוא - בביאה השנייה, עוון יוסר ביום אחד.",
  "Zechariah 4": "זרובבל יניח את היסוד של בית ה', מקדש זרובבל ותסיים אותו.",
  "Zechariah 5": "מלאך מגלה אמיתות לזכריה על ידי שימוש בייצוגים סמליים.",
  "Zechariah 6": "זכריה מכתיר את יהושע, הכהן הגדול, בדמות המשיח, הענף, שיבוא - המשיח יהיה כומר על כסאו לנצח.",
  "Zechariah 7": "האדון מוכיח צביעות בצומות - הוא קורא לעם לגלות רחמים וחמלה ולחיות חיי אלוהים.",
  "Zechariah 8": "באחרית הימים, ירושלים תקום, יהודה תיאסף, וה' יברך את עמו מעבר לכל דבר שהיה בעבר.",
  "Zechariah 9": "זכריה מדבר כמשיח - המשיח יבוא, בעל ישועה, שפל ורוכב על חמור - הוא ישחרר את השבויים מהבור - יהודה ואפרים הם כלי ה'.",
  "Zechariah 10": "יהודה ויוסף יתפזרו בין העם בארצות רחוקות - ה' ישרק להם, יאסוף אותם ויגאל אותם.",
  "Zechariah 11": "זכריה מדבר על המשיח - המשיח ייבגד תמורת שלושים כסף - הם יושלכו לקדר בבית ה'.",
  "Zechariah 12": "במלחמה הגדולה האחרונה, כל העמים יהיו מעורבים בירושלים, אבל ה' יגן על עמו - אז יביטו היהודים בה' אשר צלבו, ויהיה אבל גדול.",
  "Zechariah 13": "היהודים יזכו לסליחה בביאה השנייה - הם ישאלו את ה', מה הם הפצעים האלה בידיך? - השארית, המנוסה והמעודנת, תהיה עמו.",
  "Zechariah 14": "בביאתו השנייה ילחם ה' למען ישראל - רגליו יעמדו על הר הזיתים - הוא יהיה מלך על כל הארץ - מכות ישמידו את הרשעים.",
  "Malachi 1": "היהודים מבזים את יהוה על ידי הקרבת לחם מזוהם על המזבח ועל ידי הקרבת חיות עם פגמים - שם ה' יהיה גדול בקרב הגויים.",
  "Malachi 2": "הכוהנים ננזפים על כך שלא קיימו את בריתיהם ולא מלמדים את העם - היהודים נידונים על התנהגות בוגדנית זה עם זה ועם נשותיהם.",
  "Malachi 3": "שליח ה' יכין את הדרך לביאה השנייה - ה' ישב בדין - עם ישראל מצווה לשלם מעשר ומנחות - הם מנהלים ספר זיכרון.",
  "Malachi 4": "בביאה השנייה, הגאים והרשעים ישרפו כזיפים - אליהו ישוב לפני אותו יום גדול ואיום."
};
